import { User, Report, HalaqahEvaluation } from '../../../types';
import { getAllTeachers, getReportsByTeacher, saveHalaqahEvaluation, getHalaqahEvaluation } from '../../../services/firestoreService';
import { GoogleGenAI } from "@google/genai";
import { Button } from '../../../components/Button';
import { Sparkles, Save, User as UserIcon, Calendar, ClipboardList, AlertCircle, CheckCircle } from 'lucide-react';

export default function CoordinatorEvaluationsPage() {
  const [teachers, setTeachers] = useState<User[]>([]);
  const [selectedTeacherId, setSelectedTeacherId] = useState('');
  const [selectedMonth, setSelectedMonth] = useState('Desember');
  const [reports, setReports] = useState<Report[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const [evaluation, setEvaluation] = useState<Partial<HalaqahEvaluation>>({
    insightUtama: '',
    kendalaTerindikasi: '',
    tindakLanjut: '',
    targetBulanDepan: '',
    catatanKoordinator: ''
  });

  const months = ["Juli", "Agustus", "September", "Oktober", "November", "Desember", "Januari", "Februari", "Maret", "April", "Mei", "Juni"];

  useEffect(() => {
    getAllTeachers().then(data => {
      const onlyTeachers = data.filter(u => u.role === 'GURU');
      setTeachers(onlyTeachers);
    });
  }, []);

  useEffect(() => {
    if (selectedTeacherId && selectedMonth) {
      loadDataAndExistingEval();
    }
  }, [selectedTeacherId, selectedMonth]);

  const loadDataAndExistingEval = async () => {
    setIsLoading(true);
    const [teacherReports, existingEval] = await Promise.all([
      getReportsByTeacher(selectedTeacherId),
      getHalaqahEvaluation(selectedTeacherId, `${selectedMonth} 2025`)
    ]);

    setReports(teacherReports.filter(r => r.month === selectedMonth));

    if (existingEval) {
      setEvaluation(existingEval);
    } else {
      setEvaluation({
        insightUtama: '',
        kendalaTerindikasi: '',
        tindakLanjut: '',
        targetBulanDepan: '',
        catatanKoordinator: ''
      });
    }
    setIsLoading(false);
  };

  const handleGenerateAI = async () => {
    if (reports.length === 0) {
      alert("Tidak ada data laporan bulan ini untuk dianalisis.");
      return;
    }

    setIsGenerating(true);
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) throw new Error("API Key missing");

      const ai = new GoogleGenAI({ apiKey });

      // Persiapkan data tabel untuk AI (Manual Stringify)
      const tableData = reports.map(r => 
        `- ${r.studentName}: Tahfizh(${r.tahfizh.individual}), Notes(${r.notes})`
      ).join('\n');

      const prompt = `
        Anda adalah Koordinator Tahfizh SDQ Mutiara Sunnah.
        Tugas: Berikan evaluasi pembinaan untuk Guru Halaqah berdasarkan laporan bulanan santri berikut:

        DATA LAPORAN:
        ${tableData}

        INSTRUKSI KHUSUS:
        1. Gunakan bahasa yang santun, memotivasi, dan berwibawa.
        2. Fokus pada performa KELAS/HALAQAH secara kolektif.
        3. Output HARUS dalam format JSON dengan key: insightUtama, kendalaTerindikasi, tindakLanjut, targetBulanDepan.
        4. Jangan gunakan Markdown formatting dalam value JSON.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      const result = JSON.parse(response.text || '{}');
      setEvaluation(prev => ({ ...prev, ...result }));

    } catch (error) {
      console.error(error);
      alert("Gagal generate evaluasi AI.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = async () => {
    if (!selectedTeacherId) return;
    setIsSaving(true);
    try {
      await saveHalaqahEvaluation({
        teacherId: selectedTeacherId,
        period: `${selectedMonth} 2025`,
        academicYear: '2025/2026',
        insightUtama: evaluation.insightUtama || '',
        kendalaTerindikasi: evaluation.kendalaTerindikasi || '',
        tindakLanjut: evaluation.tindakLanjut || '',
        targetBulanDepan: evaluation.targetBulanDepan || '',
        catatanKoordinator: evaluation.catatanKoordinator || ''
      });
      alert("Evaluasi berhasil dikirim ke Guru!");
    } catch (e) {
      alert("Gagal menyimpan evaluasi.");
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-20">
      <div className="px-1">
        <h2 className="text-2xl font-bold text-gray-900">Workspace Evaluasi Halaqah</h2>
        <p className="text-gray-500 mt-1">Gunakan AI untuk menganalisis laporan bulanan guru dan berikan arahan pembinaan.</p>
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1.5 ml-1">Pilih Halaqah (Guru)</label>
          <div className="relative">
            <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
            <select value={selectedTeacherId} onChange={e => setSelectedTeacherId(e.target.value)} className="w-full pl-10 pr-4 py-2.5 border border-gray-200 rounded-xl bg-white text-sm outline-none focus:ring-2 focus:ring-primary-500">
              <option value="">-- Pilih Guru --</option>
              {teachers.map(t => <option key={t.id} value={t.id}>{t.nickname || t.name}</option>)}
            </select>
          </div>
        </div>
        <div>
          <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1.5 ml-1">Periode Laporan</label>
          <div className="relative">
            <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
            <select value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="w-full pl-10 pr-4 py-2.5 border border-gray-200 rounded-xl bg-white text-sm outline-none focus:ring-2 focus:ring-primary-500">
              {months.map(m => <option key={m} value={m}>{m} 2025</option>)}
            </select>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Panel Kiri: Referensi Data Laporan */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 flex flex-col h-[600px]">
          <div className="p-5 border-b border-gray-50 flex justify-between items-center bg-gray-50/50 rounded-t-2xl">
            <h3 className="font-bold text-gray-800 text-sm flex items-center gap-2"><ClipboardList size={18} className="text-primary-500"/> Referensi Laporan Bulanan</h3>
            <span className="text-[10px] font-bold bg-primary-100 text-primary-700 px-2 py-1 rounded-full">{reports.length} Santri</span>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
            {isLoading ? (
              <div className="h-full flex items-center justify-center text-gray-400 italic text-sm">Memuat data...</div>
            ) : reports.length > 0 ? (
              reports.map(r => (
                <div key={r.id} className="p-3 bg-gray-50 rounded-xl border border-gray-100 text-xs hover:border-primary-200 transition-colors">
                  <p className="font-bold text-gray-900 mb-1">{r.studentName}</p>
                  <p className="text-gray-500 mb-1"><span className="font-bold text-primary-600">Sabaq:</span> {r.tahfizh.individual}</p>
                  <p className="text-gray-400 italic line-clamp-2">"{r.notes || 'Tidak ada catatan guru'}"</p>
                </div>
              ))
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-gray-400">
                 <AlertCircle size={40} className="mb-2 opacity-20" />
                 <p className="text-sm">Pilih guru & periode untuk melihat data</p>
              </div>
            )}
          </div>
        </div>

        {/* Panel Kanan: Form Evaluasi Koordinator */}
        <div className="bg-white rounded-2xl shadow-sm border border-primary-100 flex flex-col">
          <div className="p-5 border-b border-primary-50 flex justify-between items-center bg-primary-50/30 rounded-t-2xl">
            <h3 className="font-bold text-primary-800 text-sm flex items-center gap-2">Formulir Pembinaan Halaqah</h3>
            <button onClick={handleGenerateAI} disabled={isGenerating || reports.length === 0} className="flex items-center gap-1.5 px-3 py-1.5 bg-primary-600 hover:bg-primary-700 text-white rounded-lg text-[10px] font-bold transition-all disabled:opacity-50">
              <Sparkles size={14} className={isGenerating ? "animate-spin" : ""} /> {isGenerating ? "Menganalisis..." : "Analisis AI"}
            </button>
          </div>
          <div className="p-6 space-y-4 overflow-y-auto max-h-[500px] custom-scrollbar">
            <div className="space-y-4">
               <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5">Insight Utama (Performa Halaqah)</label>
                  <textarea value={evaluation.insightUtama} onChange={e => setEvaluation({...evaluation, insightUtama: e.target.value})} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs focus:ring-2 focus:ring-primary-500 outline-none h-20 resize-none shadow-inner" placeholder="Pencapaian umum halaqah..." />
               </div>
               <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5">Kendala Terindikasi</label>
                  <textarea value={evaluation.kendalaTerindikasi} onChange={e => setEvaluation({...evaluation, kendalaTerindikasi: e.target.value})} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs focus:ring-2 focus:ring-primary-500 outline-none h-20 resize-none shadow-inner" placeholder="Tantangan yang perlu diperhatikan..." />
               </div>
               <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5">Arahan & Tindak Lanjut</label>
                  <textarea value={evaluation.tindakLanjut} onChange={e => setEvaluation({...evaluation, tindakLanjut: e.target.value})} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs focus:ring-2 focus:ring-primary-500 outline-none h-20 resize-none shadow-inner" placeholder="Langkah perbaikan konkret..." />
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5">Target Bulan Depan</label>
                    <input value={evaluation.targetBulanDepan} onChange={e => setEvaluation({...evaluation, targetBulanDepan: e.target.value})} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs focus:ring-2 focus:ring-primary-500 outline-none shadow-inner" placeholder="Contoh: Juz 30 Selesai" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5">Status Halaqah</label>
                    <div className="flex items-center gap-2 mt-2">
                       <CheckCircle size={16} className="text-emerald-500" />
                       <span className="text-[10px] font-bold text-emerald-600">Data Siap Dikirim</span>
                    </div>
                  </div>
               </div>
               <div>
                  <label className="block text-[10px] font-black text-primary-500 uppercase tracking-widest mb-1.5">Catatan Khusus Koordinator (Internal)</label>
                  <textarea value={evaluation.catatanKoordinator} onChange={e => setEvaluation({...evaluation, catatanKoordinator: e.target.value})} className="w-full p-3 bg-white border-2 border-primary-100 rounded-xl text-xs focus:ring-2 focus:ring-primary-500 outline-none h-16 resize-none" placeholder="Catatan tambahan untuk ustadz/ustadzah..." />
               </div>
            </div>
          </div>
          <div className="p-5 bg-gray-50 border-t border-gray-100 rounded-b-2xl">
            <Button onClick={handleSave} isLoading={isSaving} disabled={!selectedTeacherId || !evaluation.insightUtama} className="w-full py-3.5 rounded-xl font-black text-xs uppercase tracking-widest shadow-lg shadow-primary-500/20">
              <Save size={16} className="mr-2" /> Kirim Hasil Evaluasi ke Guru
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { HalaqahEvaluation } from '../../../types';
import { getLatestEvaluationForTeacher } from '../../../services/firestoreService';
import { BookOpen, Sparkles, MessageSquare, Target, Zap, AlertCircle } from 'lucide-react';

export default function GuruEvaluationPage({ teacherId }: { teacherId?: string }) {
  const [evaluation, setEvaluation] = useState<HalaqahEvaluation | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (teacherId) {
      getLatestEvaluationForTeacher(teacherId).then(data => {
        setEvaluation(data);
        setIsLoading(false);
      });
    }
  }, [teacherId]);

  if (isLoading) return <div className="p-8 text-center text-gray-400">Memuat evaluasi...</div>;

  if (!evaluation) {
    return (
      <div className="min-h-[60vh] flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-sm border border-gray-100 p-12 text-center">
          <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6 text-gray-300">
            <MessageSquare size={40} />
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">Belum Ada Evaluasi</h3>
          <p className="text-sm text-gray-500">Evaluasi dari koordinator untuk halaqah Anda belum tersedia untuk periode ini.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="relative bg-white rounded-[2.5rem] shadow-xl shadow-primary-500/5 border border-primary-50 overflow-hidden">

        {/* Header Ribbon */}
        <div className="bg-gradient-to-r from-primary-600 to-primary-800 px-8 py-10 text-white">
          <div className="flex justify-between items-start">
            <div>
              <div className="flex items-center gap-2 mb-3">
                <Sparkles size={20} className="text-primary-200" />
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-primary-100">Evaluasi & Arahan Pembinaan</span>
              </div>
              <h2 className="text-3xl font-black tracking-tight mb-2">Halaqah {evaluation.period}</h2>
              <p className="text-primary-100/80 text-sm font-medium">Berdasarkan data performa dan laporan bulanan ustadz.</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md p-4 rounded-2xl border border-white/20">
               <BookOpen size={32} className="text-white" />
            </div>
          </div>
        </div>

        {/* Content Body */}
        <div className="p-8 sm:p-12 space-y-10">

          {/* Section 1: Insight Utama */}
          <div className="space-y-4">
             <div className="flex items-center gap-3">
                <div className="p-2 bg-emerald-50 text-emerald-600 rounded-xl">
                  <Zap size={20} />
                </div>
                <h3 className="text-sm font-black text-gray-800 uppercase tracking-widest">Insight Utama</h3>
             </div>
             <div className="bg-emerald-50/30 p-6 rounded-[1.5rem] border border-emerald-100/50 leading-relaxed text-gray-700 font-medium">
                {evaluation.insightUtama}
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Section 2: Kendala */}
            <div className="space-y-4">
               <div className="flex items-center gap-3">
                  <div className="p-2 bg-orange-50 text-orange-600 rounded-xl">
                    <AlertCircle size={20} />
                  </div>
                  <h3 className="text-sm font-black text-gray-800 uppercase tracking-widest">Kendala Terindikasi</h3>
               </div>
               <div className="p-1 text-sm text-gray-600 leading-relaxed italic">
                  {evaluation.kendalaTerindikasi}
               </div>
            </div>

            {/* Section 3: Target */}
            <div className="space-y-4">
               <div className="flex items-center gap-3">
                  <div className="p-2 bg-blue-50 text-blue-600 rounded-xl">
                    <Target size={20} />
                  </div>
                  <h3 className="text-sm font-black text-gray-800 uppercase tracking-widest">Target Bulan Depan</h3>
               </div>
               <div className="bg-blue-600 p-6 rounded-[1.5rem] text-white shadow-lg shadow-blue-500/20">
                  <p className="text-[10px] font-bold uppercase opacity-60 mb-1">Capaian Minimum:</p>
                  <p className="text-xl font-black">{evaluation.targetBulanDepan}</p>
               </div>
            </div>
          </div>

          {/* Section 4: Tindak Lanjut */}
          <div className="pt-6 border-t border-gray-100">
             <div className="flex items-center gap-3 mb-4">
                <div className="p-2 bg-primary-50 text-primary-600 rounded-xl">
                  <MessageSquare size={20} />
                </div>
                <h3 className="text-sm font-black text-gray-800 uppercase tracking-widest">Tindak Lanjut & Arahan</h3>
             </div>
             <div className="bg-gray-50 p-6 rounded-[1.5rem] border border-gray-100 leading-relaxed text-gray-700">
                {evaluation.tindakLanjut}
             </div>
          </div>

          {/* Signature / Footer */}
          <div className="flex justify-between items-center pt-8">
             <div className="text-xs text-gray-400 font-medium">
                Dibuat pada: {new Date(evaluation.createdAt).toLocaleDateString('id-ID')}
             </div>
             <div className="text-right">
                <p className="text-[10px] font-black text-primary-600 uppercase tracking-widest mb-1">Koordinator Tahfizh</p>
                <div className="h-px w-24 bg-primary-100 ml-auto mb-2"></div>
                <p className="text-sm font-bold text-gray-900">SDQ Mutiara Sunnah</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
}

