      const result = await response.json();

      setEvaluation(prev => ({
        ...prev,
        insightUtama: result.insightUtama || '',
        kendalaTerindikasi: result.kendalaTerindikasi || '',
        tindakLanjut: result.tindakLanjut || '',
        targetBulanDepan: result.targetBulanDepan || ''
      }));

