        </div>
      </div>

      {/* 1. INSIGHT UTAMA (Paling Menonjol) */}
      <div className="bg-blue-50 rounded-[2.5rem] p-6 sm:p-8 border border-blue-100 shadow-lg shadow-blue-500/5">
