import React, { useEffect, useState } from 'react';
import { Report, HalaqahMonthlyReport } from '../../../types';
import { subscribeToReportsByTeacher, deleteReport, updateReport, getHalaqahMonthlyReport } from '../../../services/firestoreService';
import { calculateFromRangeString } from '../../../services/quranMapping';
import { Search, Download, Edit2, Trash2, X, FileSpreadsheet, Book, BookOpen, Database, Layers } from 'lucide-react';
import { Button } from '../../../components/Button';
import * as XLSX from 'xlsx';

interface GuruViewReportPageProps {
  teacherId?: string;
}

const formatTotalHafalan = (total: { juz: number; pages: number; lines: number } | undefined) => {
  if (!total) return '-';
  const j = Number(total.juz || 0);
  const p = Number(total.pages || 0);
  const parts = [];
  if (j > 0) parts.push(`${j} Juz`);
  if (p > 0) parts.push(`${p} Halaman`);
  return parts.length > 0 ? parts.join(' ') : '0 Juz'; 
};

export default function GuruViewReportPage({ teacherId = '1' }: GuruViewReportPageProps) {
  const [reports, setReports] = useState<Report[]>([]);
  const [filteredReports, setFilteredReports] = useState<Report[]>([]);
  const [klasikalMap, setKlasikalMap] = useState<Record<string, HalaqahMonthlyReport>>({});
  const [search, setSearch] = useState('');
  const [filterMonth, setFilterMonth] = useState('Semua');
  const [filterType, setFilterType] = useState('Semua');
  const [isLoading, setIsLoading] = useState(true);

  const [editingReport, setEditingReport] = useState<Report | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);

  useEffect(() => {
    if (!teacherId) return;
    setIsLoading(true);

    const unsubscribe = subscribeToReportsByTeacher(teacherId, async (data) => {
      setReports(data);

      // Load relevant klasikal data
      const periods = Array.from(new Set(data.map(r => r.month)));
      const maps: Record<string, HalaqahMonthlyReport> = {};
      for (const p of periods) {
        const k = await getHalaqahMonthlyReport(teacherId, p);
        if (k) maps[p] = k;
      }
      setKlasikalMap(maps);
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, [teacherId]);

  useEffect(() => {
    let result = reports;
    if (search) {
      result = result.filter(r => 
        r.studentName.toLowerCase().includes(search.toLowerCase()) ||
        (r.className || '').toLowerCase().includes(search.toLowerCase())
      );
    }
    if (filterMonth !== 'Semua') result = result.filter(r => r.month === filterMonth);
    if (filterType !== 'Semua') result = result.filter(r => r.type === filterType);
    setFilteredReports(result);
  }, [search, filterMonth, filterType, reports]);

  const getCalculationDisplay = (rangeStr: string | undefined) => {
    if (!rangeStr || rangeStr === '-' || rangeStr === '') return "-";
    const result = calculateFromRangeString(rangeStr);
    if (result.pages > 0) return `${result.pages} Halaman`;
    if (result.lines > 0) return `${result.lines} Baris`;
    return "0 Baris";
  };

  const handleExportExcel = () => {
    if (filteredReports.length === 0) return;
    const exportData = filteredReports.map((report, idx) => {
      const klasikal = klasikalMap[report.month];
      return {
        "No": idx + 1,
        "Nama Siswa": report.studentName,
        "Bulan": report.month,
        "Jumlah Hafalan": formatTotalHafalan(report.totalHafalan),
        "Klasikal Tahfizh": klasikal ? `${klasikal.klasikal.tahfizh.from}-${klasikal.klasikal.tahfizh.to}` : '-',
        "Individu Tahfizh": report.tahfizh.individual,
        "Catatan Individu": report.notes
      };
    });
    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Laporan_SDQ");
    XLSX.writeFile(workbook, `Laporan_Halaqah_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  return (
    <div className="space-y-6 max-w-[95%] mx-auto pb-12">
      <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
        <div><h2 className="text-2xl font-bold text-gray-900">Arsip Laporan</h2></div>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 flex flex-col lg:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          <input type="text" placeholder="Cari nama siswa..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none" />
        </div>
        <div className="flex gap-2">
          <select value={filterMonth} onChange={(e) => setFilterMonth(e.target.value)} className="px-4 py-2 border border-gray-300 rounded-lg bg-white text-sm outline-none">
            <option value="Semua">Semua Bulan</option>
            {["Juli", "Agustus", "September", "Oktober", "November", "Desember", "Januari", "Februari", "Maret", "April", "Mei", "Juni"].map(m => <option key={m} value={m}>{m}</option>)}
          </select>
          <Button variant="secondary" onClick={handleExportExcel}><FileSpreadsheet size={18} /></Button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse whitespace-nowrap">
            <thead>
              <tr className="bg-[#0e7490] text-white text-xs uppercase font-bold tracking-wider">
                <th className="px-4 py-3 border-r border-white/20">Nama Siswa / Periode</th>
                <th className="px-4 py-3 border-r border-white/20">Klasikal Halaqah</th>
                <th className="px-4 py-3 border-r border-white/20">Individu (Sabaq)</th>
                <th className="px-4 py-3">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 text-sm">
              {isLoading ? (
                <tr><td colSpan={4} className="px-6 py-12 text-center text-gray-500">Memuat laporan...</td></tr>
              ) : filteredReports.length > 0 ? (
                filteredReports.map((report) => {
                  const klasikal = klasikalMap[report.month];
                  return (
                    <tr key={report.id} className="hover:bg-gray-50/50">
                      <td className="px-4 py-4">
                        <div className="font-bold text-gray-900">{report.studentName}</div>
                        <div className="text-[10px] font-bold text-primary-500 uppercase">{report.month} 2025/2026</div>
                      </td>
                      <td className="px-4 py-4 bg-primary-50/30">
                        {klasikal ? (
                          <div className="space-y-1">
                             <p className="text-[10px] font-bold text-primary-700 uppercase">Tahfizh: {klasikal.klasikal.tahfizh.from} - {klasikal.klasikal.tahfizh.to}</p>
                             <p className="text-[9px] text-primary-500 italic leading-tight">"{klasikal.klasikal.tahfizh.notes}"</p>
                             <div className="h-px bg-primary-100 my-1"></div>
                             <p className="text-[10px] font-bold text-blue-700 uppercase">Tilawah: {klasikal.klasikal.tilawah.materi}</p>
                          </div>
                        ) : <span className="text-[10px] text-gray-400 italic">Data klasikal tidak ditemukan</span>}
                      </td>
                      <td className="px-4 py-4">
                        <div className="font-bold text-emerald-700 text-[11px] mb-1 uppercase">Tahfizh: {report.tahfizh.individual}</div>
                        <div className="text-[10px] text-gray-500 italic max-w-xs whitespace-normal">"{report.notes}"</div>
                      </td>
                      <td className="px-4 py-4">
                        <div className="flex gap-2">
                           <button onClick={() => alert("Edit Individu")} className="text-blue-600 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={16} /></button>
                           <button onClick={() => deleteReport(report.id)} className="text-red-600 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={16} /></button>
                        </div>
                      </td>
                    </tr>
                  );
                })
              ) : <tr><td colSpan={4} className="px-6 py-12 text-center text-gray-400 italic">Tidak ada laporan.</td></tr>}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { Student, HalaqahMonthlyReport } from '../../../types';
import { getStudentsByTeacher, saveSDQReport, saveHalaqahMonthlyReport, getHalaqahMonthlyReport } from '../../../services/firestoreService';
import { SURAH_LIST } from '../../../services/mockBackend';
import { calculateHafalan } from '../../../services/quranMapping';
import { Button } from '../../../components/Button';
import { BookOpen, Book, Plus, Minus, Database, UserCheck, Heart, Layers, Trash2 } from 'lucide-react';

interface GuruLaporanPageProps {
  teacherId?: string;
}

interface TahfizhRange {
  surah: string;
  fromAyat: string;
  toAyat: string;
}

const IQRA_VOLUMES = ["Iqra' 1", "Iqra' 2", "Iqra' 3", "Iqra' 4", "Iqra' 5", "Iqra' 6"];

const CounterInput = ({ 
  label, 
  value, 
  onChange, 
  min = 0 
}: { 
  label?: string, 
  value: number | string, 
  onChange: (v: number | string) => void, 
  min?: number 
}) => {
  const handleDecrement = () => {
    if (typeof value === 'string') onChange(min);
    else onChange(Math.max(min, Number(value) - 1));
  };
  const handleIncrement = () => {
    if (typeof value === 'string') onChange(min + 1);
    else onChange(Number(value) + 1);
  };
  return (
    <div className="flex items-center gap-1 sm:gap-2 shrink-0">
      <button onClick={handleDecrement} className="w-8 h-9 sm:h-10 rounded-lg border border-gray-200 flex items-center justify-center text-gray-400 hover:bg-gray-50 active:bg-gray-100 transition-colors shadow-sm" type="button"><Minus size={14} /></button>
      <input type="number" min={min} value={value} placeholder="-" onChange={(e) => { const val = e.target.value; if (val === '') onChange(''); else { const num = parseInt(val); if (!isNaN(num)) onChange(num); } }} className="w-10 sm:w-14 text-center font-bold border border-gray-100 py-1.5 sm:py-2 rounded-lg bg-white focus:ring-2 focus:ring-primary-500 outline-none placeholder:text-gray-300 text-sm sm:text-base shadow-sm" />
      <button onClick={handleIncrement} className="w-8 h-9 sm:h-10 rounded-lg border border-gray-200 flex items-center justify-center text-gray-400 hover:bg-gray-50 active:bg-gray-100 transition-colors shadow-sm" type="button"><Plus size={14} /></button>
      {label && <span className="text-[10px] sm:text-xs text-gray-400 ml-0.5 font-medium">{label}</span>}
    </div>
  );
};

const SourceSelect = ({ value, onChange, method, placeholder = 'Pilih...' }: { value: string, onChange: (v: string) => void, method: 'Al-Quran' | 'Iqra', placeholder?: string }) => (
  <div className="flex-1">
    <select value={value} onChange={(e) => onChange(e.target.value)} className="w-full h-9 sm:h-10 px-3 sm:px-4 py-1 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none bg-white text-xs sm:text-sm truncate shadow-sm">
      <option value="">{placeholder}</option>
      {method === 'Al-Quran' ? (
        SURAH_LIST.map((s, index) => <option key={s} value={s}>{index + 1}. {s}</option>)
      ) : (
        IQRA_VOLUMES.map((v) => <option key={v} value={v}>{v}</option>)
      )}
    </select>
  </div>
);

const InputRow = ({ label, children }: { label: string, children?: React.ReactNode }) => (
  <div className="space-y-1.5 sm:space-y-2">
    <p className="text-[10px] sm:text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">{label}</p>
    <div className="flex flex-row items-center gap-2">{children}</div>
  </div>
);

export default function GuruLaporanPage({ teacherId = '1' }: GuruLaporanPageProps) {
  const [students, setStudents] = useState<Student[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const [reportType, setReportType] = useState('Laporan Bulanan');
  const [studentId, setStudentId] = useState('');
  const [month, setMonth] = useState('Desember');

  // Data Klasikal Halaqah (State Terstruktur)
  const [klasikalTahfizhRanges, setKlasikalTahfizhRanges] = useState<TahfizhRange[]>([
    { surah: '', fromAyat: '', toAyat: '' }
  ]);
  const [klasikalTilawahMateri, setKlasikalTilawahMateri] = useState('');

  // Individual Discipline & Behavior
  const [attendance, setAttendance] = useState<number>(100);
  const [behaviorScore, setBehaviorScore] = useState<number>(10);

  // Individual Progress
  const [tilawahMethod, setTilawahMethod] = useState<'Al-Quran' | 'Iqra'>('Al-Quran');
  const [tilawahFromSurah, setTilawahFromSurah] = useState(''); 
  const [tilawahFromVerse, setTilawahFromVerse] = useState<number | string>(''); 
  const [tilawahToSurah, setTilawahToSurah] = useState('');
  const [tilawahToVerse, setTilawahToVerse] = useState<number | string>(''); 
  const [tilawahTotal, setTilawahTotal] = useState({ pages: 0, lines: 0 });

  const [tahfizhFromSurah, setTahfizhFromSurah] = useState(''); 
  const [tahfizhFromVerse, setTahfizhFromVerse] = useState<number | string>(''); 
  const [tahfizhToSurah, setTahfizhToSurah] = useState('');
  const [tahfizhToVerse, setTahfizhToVerse] = useState<number | string>(''); 
  const [tahfizhTotal, setTahfizhTotal] = useState({ pages: 0, lines: 0 });

  const [baselineJuz, setBaselineJuz] = useState<number | string>(0);
  const [baselinePages, setBaselinePages] = useState<number | string>(0);
  const [baselineLines, setBaselineLines] = useState<number | string>(0);
  const [notes, setNotes] = useState('');

  // Load Klasikal Data based on Period
  useEffect(() => {
    const loadKlasikal = async () => {
      if (!teacherId || !month) return;
      const existing = await getHalaqahMonthlyReport(teacherId, month);
      if (existing) {
        // Parsing data string "Surah: From-To, Surah: From-To" kembali ke array
        const rawFrom = existing.klasikal.tahfizh.from || '';
        if (rawFrom.includes(':')) {
            const rangeStrings = rawFrom.split(', ');
            const parsedRanges = rangeStrings.map(str => {
                const [surah, range] = str.split(': ');
                const [from, to] = range.split('-');
                return { surah, fromAyat: from, toAyat: to };
            });
            setKlasikalTahfizhRanges(parsedRanges);
        } else {
            setKlasikalTahfizhRanges([{ surah: '', fromAyat: '', toAyat: '' }]);
        }
        setKlasikalTilawahMateri(existing.klasikal.tilawah.materi);
      } else {
        setKlasikalTahfizhRanges([{ surah: '', fromAyat: '', toAyat: '' }]);
        setKlasikalTilawahMateri('');
      }
    };
    loadKlasikal();
  }, [teacherId, month]);

  useEffect(() => {
    const loadData = async () => {
      if (!teacherId) return;
      setIsLoading(true);
      try { const data = await getStudentsByTeacher(teacherId); setStudents(data); } finally { setIsLoading(false); }
    };
    loadData();
  }, [teacherId]);

  const safeNum = (val: string | number) => (typeof val === 'number' ? val : 0);

  useEffect(() => {
    const result = calculateHafalan(tilawahFromSurah, safeNum(tilawahFromVerse), tilawahToSurah, safeNum(tilawahToVerse));
    setTilawahTotal(result);
  }, [tilawahMethod, tilawahFromSurah, tilawahFromVerse, tilawahToSurah, tilawahToVerse]);

  useEffect(() => {
    const result = calculateHafalan(tahfizhFromSurah, safeNum(tahfizhFromVerse), tahfizhToSurah, safeNum(tahfizhToVerse));
    setTahfizhTotal(result);
  }, [tahfizhFromSurah, tahfizhFromVerse, tahfizhToSurah, tahfizhToVerse]);

  const addTahfizhRange = () => {
    setKlasikalTahfizhRanges([...klasikalTahfizhRanges, { surah: '', fromAyat: '', toAyat: '' }]);
  };

  const removeTahfizhRange = (index: number) => {
    if (klasikalTahfizhRanges.length <= 1) return;
    const newRanges = [...klasikalTahfizhRanges];
    newRanges.splice(index, 1);
    setKlasikalTahfizhRanges(newRanges);
  };

  const updateTahfizhRange = (index: number, field: keyof TahfizhRange, value: string) => {
    const newRanges = [...klasikalTahfizhRanges];
    newRanges[index][field] = value;
    setKlasikalTahfizhRanges(newRanges);
  };

  const handleSave = async () => {
    if (!studentId) { alert("Mohon pilih siswa terlebih dahulu."); return; }
    const selectedStudent = students.find(s => s.id === studentId);
    if (!selectedStudent) return;

    setIsSaving(true);
    try {
      // Serialisasi array range menjadi string: "Surah: Awal-Akhir"
      const serializedTahfizh = klasikalTahfizhRanges
        .filter(r => r.surah && r.fromAyat && r.toAyat)
        .map(r => `${r.surah}: ${r.fromAyat}-${r.toAyat}`)
        .join(', ');

      // 1. Simpan/Update Data Klasikal (Global Halaqah)
      await saveHalaqahMonthlyReport({
        halaqahId: teacherId,
        teacherId: teacherId,
        period: month,
        academicYear: '2025/2026',
        klasikal: {
          tahfizh: { from: serializedTahfizh, to: '', notes: '' },
          tilawah: { materi: klasikalTilawahMateri, notes: '' }
        }
      });

      // 2. Simpan Data Individu Siswa
      const fmt = (surah: string, verse: number | string) => {
        if (!surah) return '-';
        return `${surah}: ${(typeof verse === 'string' && verse === '') ? '-' : verse}`;
      };
      const makeRange = (fs: string, fv: number | string, ts: string, tv: number | string) => {
        if (!fs && !ts) return '-';
        return `${fmt(fs, fv)} - ${fmt(ts, tv)}`;
      };

      await saveSDQReport({
        studentId, 
        studentName: selectedStudent.name, 
        teacherId, 
        className: selectedStudent.className, 
        type: reportType, 
        month, 
        academicYear: '2025/2026', 
        date: new Date().toISOString().split('T')[0], 
        evaluation: '',
        attendance,
        behaviorScore,
        tilawah: { 
          method: tilawahMethod, 
          individual: makeRange(tilawahFromSurah, tilawahFromVerse, tilawahToSurah, tilawahToVerse)
        },
        tahfizh: { 
          individual: makeRange(tahfizhFromSurah, tahfizhFromVerse, tahfizhToSurah, tahfizhToVerse)
        },
        totalHafalan: reportType === 'Laporan Semester' ? { 
          juz: safeNum(baselineJuz), 
          pages: safeNum(baselinePages), 
          lines: safeNum(baselineLines) 
        } : undefined, 
        notes
      });

      alert("Laporan berhasil disimpan!");
      setTahfizhFromSurah(''); setTahfizhToSurah('');
      setTahfizhFromVerse(''); setTahfizhToVerse('');
      setNotes('');
    } catch (error) { console.error(error); alert("Gagal menyimpan laporan."); } finally { setIsSaving(false); }
  };

  if (isLoading) return <div className="p-8 text-center text-gray-500">Memuat data...</div>;

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12">
      <div className="flex justify-between items-center px-1"><h2 className="text-2xl font-bold text-gray-900">Input Laporan Halaqah</h2></div>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 grid grid-cols-1 md:grid-cols-2 gap-6">
        <div><label className="block text-xs font-bold text-gray-400 uppercase mb-1.5 ml-1">Periode Laporan</label><select value={month} onChange={(e) => setMonth(e.target.value)} className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none bg-white text-sm">{(["Juli", "Agustus", "September", "Oktober", "November", "Desember", "Januari", "Februari", "Maret", "April", "Mei", "Juni"].map(m => <option key={m} value={m}>{m} 2025/2026</option>))}</select></div>
        <div><label className="block text-xs font-bold text-gray-400 uppercase mb-1.5 ml-1">Tipe Laporan</label><select value={reportType} onChange={(e) => setReportType(e.target.value)} className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none bg-white text-sm"><option value="Laporan Bulanan">Laporan Bulanan</option><option value="Laporan Semester">Laporan Semester (Individu)</option></select></div>
      </div>

      {/* SECTION KLASIKAL (SINGLE INPUT PER PERIOD) */}
      <div className="bg-white rounded-[2rem] shadow-sm border-2 border-primary-50 overflow-hidden">
        <div className="bg-primary-50 px-6 py-4 flex items-center justify-between border-b border-primary-100">
           <div className="flex items-center gap-3">
             <Layers className="text-primary-600" />
             <div>
                <h3 className="font-bold text-primary-900 text-sm uppercase">Capaian Klasikal Halaqah</h3>
                <p className="text-[10px] text-primary-600 font-medium italic">Input sekali untuk seluruh anggota halaqah periode {month}</p>
             </div>
           </div>
           <span className="bg-white text-primary-600 px-3 py-1 rounded-full text-[9px] font-black uppercase border border-primary-100 shadow-sm">Global Data</span>
        </div>

        <div className="p-6 space-y-8">
           {/* Tahfizh Klasikal Terstruktur */}
           <div className="space-y-4">
              <div className="flex justify-between items-center">
                 <h4 className="text-[11px] font-black text-gray-700 uppercase tracking-widest flex items-center gap-2">
                   <Book size={14} className="text-emerald-500" /> Tahfizh Klasikal (Materi Bersama)
                 </h4>
                 <button onClick={addTahfizhRange} className="flex items-center gap-1 px-2 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[10px] font-bold hover:bg-emerald-100 transition-colors">
                    <Plus size={12} /> Tambah Baris
                 </button>
              </div>

              <div className="space-y-3">
                 {klasikalTahfizhRanges.map((range, idx) => (
                    <div key={idx} className="flex flex-col sm:flex-row items-start sm:items-center gap-2 bg-gray-50/50 p-2 rounded-xl border border-gray-100 animate-in fade-in slide-in-from-left-2 duration-200">
                       <div className="w-full sm:flex-1">
                          <SourceSelect 
                             value={range.surah} 
                             onChange={(v) => updateTahfizhRange(idx, 'surah', v)} 
                             method="Al-Quran" 
                             placeholder="Pilih Surat..."
                          />
                       </div>
                       <div className="flex items-center gap-2 w-full sm:w-auto">
                          <input 
                            type="number" 
                            value={range.fromAyat} 
                            onChange={(e) => updateTahfizhRange(idx, 'fromAyat', e.target.value)} 
                            className="w-16 sm:w-20 p-2 border rounded-lg text-sm font-bold text-center" 
                            placeholder="Awal" 
                          />
                          <span className="text-gray-400 font-bold">-</span>
                          <input 
                            type="number" 
                            value={range.toAyat} 
                            onChange={(e) => updateTahfizhRange(idx, 'toAyat', e.target.value)} 
                            className="w-16 sm:w-20 p-2 border rounded-lg text-sm font-bold text-center" 
                            placeholder="Akhir" 
                          />
                          <button 
                            onClick={() => removeTahfizhRange(idx)} 
                            disabled={klasikalTahfizhRanges.length <= 1}
                            className="p-2 text-gray-300 hover:text-rose-500 disabled:opacity-0 transition-colors"
                          >
                             <Trash2 size={16} />
                          </button>
                       </div>
                    </div>
                 ))}
              </div>
           </div>

           {/* Tilawah Klasikal */}
           <div className="space-y-4 pt-4 border-t border-gray-50">
              <h4 className="text-[11px] font-black text-gray-700 uppercase tracking-widest flex items-center gap-2">
                <BookOpen size={14} className="text-blue-500" /> Materi Tilawah Klasikal
              </h4>
              <div className="flex gap-2">
                 <div className="flex-1">
                    <input 
                       value={klasikalTilawahMateri} 
                       onChange={e => setKlasikalTilawahMateri(e.target.value)} 
                       placeholder="Contoh: Juz Amma atau Al-Baqarah (1-100)" 
                       className="w-full p-3 bg-gray-50/50 border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-primary-500 outline-none" 
                    />
                 </div>
              </div>
           </div>
        </div>
      </div>

      {/* INDIVIDUAL SECTION */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 space-y-6 border-t-4 border-t-emerald-500">
        <div className="flex items-center gap-2 mb-2">
           <UserCheck className="text-emerald-600" />
           <h3 className="font-bold text-gray-800 text-sm uppercase">Capaian Individu Siswa</h3>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div><label className="block text-xs font-bold text-gray-400 uppercase mb-1.5 ml-1">Nama Siswa</label><select value={studentId} onChange={(e) => setStudentId(e.target.value)} className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none bg-white text-sm"><option value="">-- Pilih Siswa --</option>{students.map(s => <option key={s.id} value={s.id}>{s.name} - {s.className}</option>)}</select></div>
          <div className="grid grid-cols-2 gap-4">
             <div className="space-y-2">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Hadir</label>
                <select value={attendance} onChange={e => setAttendance(Number(e.target.value))} className="w-full p-2 border rounded-lg text-sm">
                   <option value={97}>Sangat Baik</option><option value={90}>Baik</option><option value={80}>Cukup</option><option value={60}>Perlu Perhatian</option>
                </select>
             </div>
             <div className="space-y-2">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Adab</label>
                <select value={behaviorScore} onChange={e => setBehaviorScore(Number(e.target.value))} className="w-full p-2 border rounded-lg text-sm">
                   <option value={10}>Sangat Baik</option><option value={8}>Baik</option><option value={6}>Perlu Pembinaan</option>
                </select>
             </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pt-4">
          {/* Tahfizh Individu */}
          <div className="space-y-4">
            <div className="flex justify-between items-center"><h4 className="text-xs font-bold text-emerald-700">Setoran Sabaq Individu</h4><span className="text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded">Total: {tahfizhTotal.pages} Hal</span></div>
            <InputRow label="DARI"><SourceSelect value={tahfizhFromSurah} onChange={(v) => {setTahfizhFromSurah(v); if(!tahfizhToSurah) setTahfizhToSurah(v);}} method="Al-Quran" /><CounterInput label="Ayat" value={tahfizhFromVerse} onChange={setTahfizhFromVerse} /></InputRow>
            <InputRow label="SAMPAI"><SourceSelect value={tahfizhToSurah} onChange={setTahfizhToSurah} method="Al-Quran" /><CounterInput label="Ayat" value={tahfizhToVerse} onChange={setTahfizhToVerse} /></InputRow>
          </div>

          {/* Tilawah Individu */}
          <div className="space-y-4">
            <div className="flex justify-between items-center"><h4 className="text-xs font-bold text-blue-700">Tilawah Individu</h4><span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded">Total: {tilawahTotal.pages} Hal</span></div>
            <div className="flex gap-2"><button onClick={() => setTilawahMethod('Al-Quran')} className={`flex-1 py-1 text-[9px] font-bold rounded-lg ${tilawahMethod === 'Al-Quran' ? 'bg-blue-600 text-white' : 'bg-gray-50 text-gray-400'}`}>AL-QUR'AN</button><button onClick={() => setTilawahMethod('Iqra')} className={`flex-1 py-1 text-[9px] font-bold rounded-lg ${tilawahMethod === 'Iqra' ? 'bg-blue-600 text-white' : 'bg-gray-50 text-gray-400'}`}>IQRA'</button></div>
            <InputRow label="DARI"><SourceSelect value={tilawahFromSurah} onChange={(v) => {setTilawahFromSurah(v); if(!tilawahToSurah) setTilawahToSurah(v);}} method={tilawahMethod} /><CounterInput label={tilawahMethod === 'Al-Quran' ? 'Ayat' : 'Hal'} value={tilawahFromVerse} onChange={setTilawahFromVerse} /></InputRow>
            <InputRow label="SAMPAI"><SourceSelect value={tilawahToSurah} onChange={setTilawahToSurah} method={tilawahMethod} /><CounterInput label={tilawahMethod === 'Al-Quran' ? 'Ayat' : 'Hal'} value={tilawahToVerse} onChange={setTilawahToVerse} /></InputRow>
          </div>
        </div>

        {reportType === 'Laporan Semester' && (
          <div className="bg-emerald-50/30 p-4 rounded-xl border border-emerald-100/50">
            <div className="flex items-center gap-2 mb-4"><Database size={16} className="text-emerald-600"/><h4 className="font-bold text-emerald-800 text-xs">Akumulasi Akhir Semester</h4></div>
            <div className="grid grid-cols-3 gap-2">
              <div className="text-center"><p className="text-[9px] font-bold text-emerald-600 mb-1 uppercase">Juz</p><CounterInput value={baselineJuz} onChange={setBaselineJuz} /></div>
              <div className="text-center"><p className="text-[9px] font-bold text-emerald-600 mb-1 uppercase">Hal</p><CounterInput value={baselinePages} onChange={setBaselinePages} /></div>
              <div className="text-center"><p className="text-[9px] font-bold text-emerald-600 mb-1 uppercase">Baris</p><CounterInput value={baselineLines} onChange={setBaselineLines} /></div>
            </div>
          </div>
        )}

        <div className="pt-4"><label className="block text-xs font-bold text-gray-400 uppercase mb-3 ml-1">Catatan Perkembangan Individu</label><textarea value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Tuliskan catatan khusus untuk siswa ini..." className="w-full h-24 p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-primary-500 outline-none resize-none text-sm placeholder:text-gray-300 shadow-sm"></textarea></div>
      </div>

      <div className="px-2"><Button onClick={handleSave} className="w-full py-4 rounded-2xl shadow-lg shadow-primary-500/20 font-bold" isLoading={isSaving}>Simpan Laporan Sekarang</Button></div>
    </div>
  );
}

