const CounterInput = ({ 
  label, 
  value, 
  onChange, 
  min = 0 
}: { 
  label?: string, 
  value: number | string, 
  onChange: (v: number) => void, 
  min?: number 
}) => {
  return (
    <div className="flex items-center gap-1 sm:gap-2 shrink-0">
      <button 
        type="button"
        onClick={() => onChange(Math.max(min, Number(value) - 1))} 
