import { subscribeToEvaluationsByTeacher } from '../../../services/firestoreService';
import { 
  BookOpen, 
  MessageSquare, 
  Target, 
  Lightbulb, 
  AlertCircle, 
  Loader2,
  CheckCircle2,
  ChevronRight,
  Zap,
  PauseCircle,
  RefreshCcw,
