/**
 * Menghitung ulang total hafalan siswa dari nol berdasarkan riwayat laporan.
 * Idempotent dan aman untuk data historis.
 */
export const recalculateTotalHafalan = async (studentId: string): Promise<void> => {
  if (!db) return;

  const studentRef = doc(db, 'siswa', studentId);
  const reportsQuery = query(
    collection(db, 'laporan'), 
    where('studentId', '==', studentId),
    orderBy('createdAt', 'asc') // Urutan kronologis input
  );

  const reportsSnap = await getDocs(reportsQuery);
  const allReports = reportsSnap.docs.map(d => ({ id: d.id, ...d.data() } as Report));

  let totalPagesAccumulated = 0;

  // Aturan: Cari "Laporan Semester" TERAKHIR sebagai baseline, 
  // lalu tambahkan "Laporan Bulanan" setelahnya.

  // 1. Cari index semester terbaru (paling akhir di array asc)
  let lastSemesterIdx = -1;
  for (let i = allReports.length - 1; i >= 0; i--) {
    if (allReports[i].type === 'Laporan Semester') {
      lastSemesterIdx = i;
      break;
    }
  }

  if (lastSemesterIdx !== -1) {
    // Jalur A: Ada Baseline Semester
    const baselineReport = allReports[lastSemesterIdx];
    // Baseline semester diambil dari input manual "Akumulasi Hafalan" di form
    const baseJuz = Number(baselineReport.totalHafalan?.juz || 0);
    const basePages = Number(baselineReport.totalHafalan?.pages || 0);
    totalPagesAccumulated = (baseJuz * 20) + basePages;

    // Tambahkan delta dari laporan bulanan yang masuk SETELAH semester ini
    for (let i = lastSemesterIdx + 1; i < allReports.length; i++) {
      if (allReports[i].type === 'Laporan Bulanan') {
        const delta = calculateFromRangeString(allReports[i].tahfizh.individual);
        totalPagesAccumulated += Number(delta.pages || 0);
      }
    }
  } else {
    // Jalur B: Tidak ada semester sama sekali (Murni Bulanan)
    allReports.forEach(report => {
      if (report.type === 'Laporan Bulanan') {
        const delta = calculateFromRangeString(report.tahfizh.individual);
        totalPagesAccumulated += Number(delta.pages || 0);
      }
    });
  }

  // Konversi kembali ke format {juz, pages} (Aturan SDQ: 1 Juz = 20 Hal)
  const finalHafalan = {
    juz: Math.floor(totalPagesAccumulated / 20),
    pages: totalPagesAccumulated % 20,
    lines: 0
  };

  // Update data master siswa
  await updateDoc(studentRef, {
    totalHafalan: finalHafalan,
    lastRecalculated: serverTimestamp()
  });
};

