export const saveSDQReport = async (reportData: Omit<Report, 'id' | 'createdAt'>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");

  // 1. Buat ID Deterministik (Idempotent)
  // Format: {studentId}_{Year}_{Month/Semester}_{Type}
  const safeYear = (reportData.academicYear || '2025-2026').replace(/\//g, '-');
  const safePeriod = reportData.month.replace(/\s/g, '_');
  const safeType = reportData.type === 'Laporan Bulanan' ? 'bulanan' : 'semester';
  const deterministicId = `${reportData.studentId}_${safeYear}_${safePeriod}_${safeType}`;

  const reportRef = doc(db, 'laporan', deterministicId);

  // 2. Simpan Laporan
  await setDoc(reportRef, {
    ...reportData,
    id: deterministicId,
    createdAt: new Date().toISOString() // Gunakan ISO string agar bisa diorder oleh Firestore
  });

  // 3. Trigger Recalculate
  await recalculateTotalHafalan(reportData.studentId);
};

export const deleteReport = async (reportId: string): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");

  const reportRef = doc(db, 'laporan', reportId);
  const reportSnap = await getDoc(reportRef);

  if (reportSnap.exists()) {
    const studentId = reportSnap.data().studentId;
    // Hapus dokumen
    await deleteDoc(reportRef);
    // Hitung ulang setelah dihapus
    await recalculateTotalHafalan(studentId);
  }
};

export const updateReport = async (reportId: string, data: Partial<Report>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");

  const reportRef = doc(db, 'laporan', reportId);
  await updateDoc(reportRef, { ...data, updatedAt: serverTimestamp() });

  // Jika field yang diupdate berpengaruh ke hafalan, hitung ulang
  const reportSnap = await getDoc(reportRef);
  if (reportSnap.exists()) {
    await recalculateTotalHafalan(reportSnap.data().studentId);
  }
};

