 * --- REVISED DATA SERVICES ---
 */

export const saveSDQReport = async (reportData: Omit<Report, 'id' | 'createdAt'>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");

  // Create Deterministic ID for Idempotency
  const safeYear = (reportData.academicYear || '2025-2026').replace(/\//g, '-').replace(/\s/g, '');
  const safeMonth = reportData.month.replace(/\s/g, '_');
  const safeType = reportData.type.toLowerCase().includes('semester') ? 'semester' : 'bulanan';
  const deterministicId = `${reportData.studentId}_${safeYear}_${safeMonth}_${safeType}`;

  const reportRef = doc(db, 'laporan', deterministicId);

  // Gunakan setDoc (bukan addDoc) untuk memastikan Idempotent Write
  await setDoc(reportRef, {
    ...reportData,
    id: deterministicId,
    createdAt: serverTimestamp(), // Menggunakan Timestamp asli untuk sorting akurat
    updatedAt: serverTimestamp()
  });

  // Trigger recalculation setiap kali ada report baru/update
  await recalculateTotalHafalan(reportData.studentId);
};

export const updateReport = async (reportId: string, data: Partial<Report>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");

