// Added missing ClassSummary interface for use in CoordinatorKelasPage
export interface ClassSummary {
  className: string;
  totalStudents: number;
  status: string;
  halaqahs: { teacherName: string, studentCount: number }[];
}

/**
 * --- RECALCULATION ENGINE (CORE) ---
 * Menghitung ulang total hafalan siswa dari nol berdasarkan riwayat laporan di Firestore.
 * Aturan: Laporan Semester = Baseline, Laporan Bulanan = Delta.
 */
export const recalculateTotalHafalan = async (studentId: string): Promise<void> => {
  if (!db) return;

  const studentRef = doc(db, 'siswa', studentId);
  const reportsQuery = query(
    collection(db, 'laporan'), 
    where('studentId', '==', studentId),
    orderBy('createdAt', 'asc') // Pastikan urutan kronologis benar
  );

  const reportsSnap = await getDocs(reportsQuery);
  const allReports = reportsSnap.docs.map(d => ({ 
    ...d.data(), 
    id: d.id 
  }) as Report);

  let totalPagesAccumulated = 0;

  // 1. Identifikasi Baseline (Cari Semester Report Terakhir)
  let lastSemesterIdx = -1;
  for (let i = allReports.length - 1; i >= 0; i--) {
    if (allReports[i].type === 'Laporan Semester') {
      lastSemesterIdx = i;
      break;
    }
  }

  if (lastSemesterIdx !== -1) {
    const baseline = allReports[lastSemesterIdx];
    // Konversi Juz & Halaman ke Total Halaman (Aturan SDQ: 1 Juz = 20 Hal)
    const baseJuz = Number(baseline.totalHafalan?.juz || 0);
    const basePages = Number(baseline.totalHafalan?.pages || 0);
    totalPagesAccumulated = (baseJuz * 20) + basePages;

    // 2. Tambahkan Delta (Hanya Laporan Bulanan SETELAH semester baseline)
    for (let i = lastSemesterIdx + 1; i < allReports.length; i++) {
      if (allReports[i].type === 'Laporan Bulanan') {
        const rangeStr = allReports[i].tahfizh?.individual;
        // Guard: Jangan hitung jika data kosong atau tanda "-"
        if (rangeStr && rangeStr !== '-' && rangeStr.trim() !== '') {
          const delta = calculateFromRangeString(rangeStr);
          totalPagesAccumulated += Number(delta.pages || 0);
        }
      }
    }
  } else {
    // 3. Fallback: Hitung murni dari seluruh Laporan Bulanan jika tidak ada semester
    allReports.forEach(r => {
      if (r.type === 'Laporan Bulanan') {
        const rangeStr = r.tahfizh?.individual;
        if (rangeStr && rangeStr !== '-' && rangeStr.trim() !== '') {
          const delta = calculateFromRangeString(rangeStr);
          totalPagesAccumulated += Number(delta.pages || 0);
        }
      }
    });
  }

  // 4. Transformasi Balik ke Format Objek (Juz, Pages)
  const finalHafalan = {
    juz: Math.floor(totalPagesAccumulated / 20),
    pages: totalPagesAccumulated % 20,
    lines: 0
  };

  // 5. Update Master Data Siswa
  await updateDoc(studentRef, {
    totalHafalan: finalHafalan,
    lastSyncAt: serverTimestamp()
  });
};

