            to: klasikalTilawah.type === 'quran' ? { surah: klasikalTilawah.to.surah, ayah: klasikalTilawah.to.ayah } : { jilid: klasikalTilawah.to.jilid, halaman: klasikalTilawah.to.halaman },
          }
