      const fmt = (surah: string, verse: number | string) => (surah ? `${surah}: ${verse === '' ? '-' : verse}` : '-');
      const makeRange = (fs: string, fv: number | string, ts: string, tv: number | string) => (!fs && !ts ? '-' : `${fmt(fs, fv)} - ${fmt(ts, tv)}`);

      await saveSDQReport({
