import { QuranAyahData } from './types';
import { QURAN_FULL_MAP } from './quranFullData';
import { QURAN_METADATA } from './quranData';

/**
 * HASIL PERHITUNGAN SAFE
 * Struktur return standar untuk menghindari undefined/null di UI
 */
export interface SafeCalculationResult {
  valid: boolean;
  pages: number;
  lines: number;
  totalLines: number;
  reason?: string; // Untuk debugging / warning UI
}

export class TahfizhEngineSDQ {
  private static readonly LINES_PER_PAGE = 15;

  /**
   * 1️⃣ NORMALISASI SURAH (LOGIC WAJIB)
   * Menstandarisasi input user agar cocok dengan key di database.
   * Contoh: "al 'imran" -> "Ali 'Imran", "Al-baqarah" -> "Al-Baqarah"
   */
  private static normalizeSurahName(input: string): string {
    if (!input) return "";

    let normalized = input.toLowerCase().trim();

    // Samakan tanda kutip (‘ ’ `) -> '
    normalized = normalized.replace(/['`’‘]/g, "'");

    // Samakan "al " -> "al-"
    normalized = normalized.replace(/\bal\s+/g, "al-");

    // Mapping manual untuk case khusus yang sering typo
    const typoMap: Record<string, string> = {
      "ali imran": "Ali 'Imran",
      "al-imran": "Ali 'Imran",
      "al imran": "Ali 'Imran",
      "yasin": "Ya-Sin",
      "ya sin": "Ya-Sin",
      "amma": "An-Naba'",
      "an naba": "An-Naba'",
      "al-lahab": "Al-Lahab", // Kadang ditulis Al-Masad
      "al masad": "Al-Lahab"
    };

    if (typoMap[normalized]) return typoMap[normalized];

    // Capitalize setiap kata untuk pencarian di Metadata (Al-Baqarah)
    return normalized.replace(/\b\w/g, l => l.toUpperCase());
  }

  /**
   * 2️⃣ PENENTUAN POSISI SDQ (LOGIC WAJIB)
   * Mengambil koordinat fisik (Juz, Halaman, Baris)
   */
  private static getCoordinates(surahRaw: string, ayahRaw: number): QuranAyahData | null {
    const surahName = this.normalizeSurahName(surahRaw);

    // 1. Coba Cari Exact Match di Metadata untuk validasi nama surah
    const metaKey = Object.keys(QURAN_METADATA).find(k => 
      this.normalizeSurahName(k) === surahName
    );

    if (!metaKey) return null; // Surah tidak ditemukan

    const meta = QURAN_METADATA[metaKey];

    // Validasi range ayat
    if (ayahRaw < 1 || ayahRaw > meta.totalAyah) return null;

    // 2. Coba Cari di QURAN_FULL_MAP (Prioritas Tinggi - Data Presisi)
    // Key di FullMap harus konsisten, misal "Al-Baqarah:1"
    const exactKey = `${metaKey}:${ayahRaw}`;
    if (QURAN_FULL_MAP[exactKey]) {
      return QURAN_FULL_MAP[exactKey];
    }

    // 3. Fallback: Estimasi Linear (Jika data per-ayat belum lengkap)
    // Rumus interpolasi posisi
    const totalPages = meta.endPage - meta.startPage + 1;
    const progress = (ayahRaw - 1) / meta.totalAyah;

    const estimatedPage = meta.startPage + Math.floor(progress * totalPages);
    // Estimasi baris (kasar)
    const estimatedLine = Math.floor(((progress * totalPages) % 1) * this.LINES_PER_PAGE) + 1;

    // Estimasi Juz (Sangat kasar, tapi cukup untuk sorting)
    let estimatedJuz = 1;
    if (estimatedPage >= 582) estimatedJuz = 30;
    else estimatedJuz = Math.ceil(estimatedPage / 20);

    return {
      juz: estimatedJuz,
      page: estimatedPage,
      line: Math.max(1, Math.min(15, estimatedLine))
    };
  }

  /**
   * 3️⃣ PERHITUNGAN VOLUME (CORE LOGIC)
   * Menghitung selisih mutlak fisik Mushaf.
   */
  public static calculateRange(fromRaw: string, fromAyah: number, toRaw: string, toAyah: number): SafeCalculationResult {
    try {
      const startCoord = this.getCoordinates(fromRaw, fromAyah);
      const endCoord = this.getCoordinates(toRaw, toAyah);

      // VALIDASI FAIL-SAFE
      if (!startCoord || !endCoord) {
        return { valid: false, pages: 0, lines: 0, totalLines: 0, reason: "Surah/Ayat tidak valid" };
      }

      // 4️⃣ CEK LOGIKA "TERBALIK"
      // Hitung posisi absolut baris dari awal mushaf (Halaman 1, Baris 1)
      const absStart = (startCoord.page * this.LINES_PER_PAGE) + startCoord.line;
      const absEnd = (endCoord.page * this.LINES_PER_PAGE) + endCoord.line;

      if (absEnd < absStart) {
        return { 
          valid: false, 
          pages: 0, 
          lines: 0, 
          totalLines: 0, 
          reason: "Range Terbalik (End < Start)" 
        };
      }

      // 5️⃣ PERHITUNGAN BARIS
      // Rumus: (Selisih Halaman * 15) + (Selisih Baris) + 1 (Inklusif)
      // Contoh: Hal 10 Brs 15 s/d Hal 11 Brs 2
      // (1 * 15) + (2 - 15) = 15 - 13 = 2 baris salah.
      // Rumus Benar: Total Baris Akhir - Total Baris Awal + 1
      // (11*15 + 2) - (10*15 + 15) + 1 = 167 - 165 + 1 = 3 baris (salah hitung manual).
      // Mari gunakan logic visual:
      // Dari Hal 10 Baris 15 (sisa 1 baris di hal 10) + Hal 11 Baris 1 & 2 (2 baris) = 3 baris. Correct.

      const totalLinesDiff = absEnd - absStart + 1; // Inklusif

      // 6️⃣ KONVERSI BARIS -> HALAMAN
      const pages = Math.floor(totalLinesDiff / this.LINES_PER_PAGE);
      const lines = totalLinesDiff % this.LINES_PER_PAGE;

      return {
        valid: true,
        pages,
        lines,
        totalLines: totalLinesDiff
      };

    } catch (e) {
      console.warn("Calculation Engine Error:", e);
      return { valid: false, pages: 0, lines: 0, totalLines: 0, reason: "Internal Error" };
    }
  }

  /**
   * PARSING AMAN STRING RANGE
   * Menerima format:
   * 1. "An-Naba: 1 - An-Naba: 40"
   * 2. "An-Naba: 1 - 40" (Short format)
   * 3. "-" atau string kosong
   */
  public static parseAndCalculate(rangeStr: string): SafeCalculationResult {
    if (!rangeStr || rangeStr.trim() === '-' || rangeStr.trim() === '') {
      return { valid: true, pages: 0, lines: 0, totalLines: 0, reason: "Empty Input" };
    }

    try {
      // Split " - "
      // Gunakan regex yang menangkap tanda hubung pemisah range, bukan tanda hubung nama surat (Al-Mulk)
      // Asumsi format standar "X - Y" (dengan spasi)
      const parts = rangeStr.split(/\s+-\s+/); 

      if (parts.length < 2) {
        // Fallback jika user tidak pakai spasi "Al-Mulk:1-Al-Mulk:5"
        // Agak berisiko tabrakan dengan nama surat, tapi kita coba split terakhir
        // Setup manual regex split jika perlu. Saat ini return invalid dulu.
        return { valid: false, pages: 0, lines: 0, totalLines: 0, reason: "Format Invalid" };
      }

      const startRaw = parts[0].trim();
      let endRaw = parts[1].trim();

      // Parse Start
      // Regex: Menangkap (Nama Surat) : (Angka)
      const startMatch = startRaw.match(/^(.*?)\s*[:]\s*(\d+)$/);
      if (!startMatch) return { valid: false, pages: 0, lines: 0, totalLines: 0, reason: "Start Invalid" };

      const startSurah = startMatch[1];
      const startAyah = parseInt(startMatch[2]);

      // Parse End
      let endSurah = startSurah;
      let endAyah = 0;

      // Cek apakah endRaw hanya angka (Format pendek: "1 - 10")
      if (/^\d+$/.test(endRaw)) {
        endAyah = parseInt(endRaw);
      } else {
        // Format panjang: "Surah : Ayat"
        const endMatch = endRaw.match(/^(.*?)\s*[:]\s*(\d+)$/);
        if (endMatch) {
          endSurah = endMatch[1];
          endAyah = parseInt(endMatch[2]);
        } else {
          return { valid: false, pages: 0, lines: 0, totalLines: 0, reason: "End Invalid" };
        }
      }

      return this.calculateRange(startSurah, startAyah, endSurah, endAyah);

    } catch (e) {
      return { valid: false, pages: 0, lines: 0, totalLines: 0, reason: "Parse Error" };
    }
  }
}

