  const [month, setMonth] = useState('Desember');

  // Default State Klasikal (Value '' agar dropdown "Pilih...")
  const [klasikalTahfizh, setKlasikalTahfizh] = useState<{
    from: { surah: string; ayah: number | string };
    to: { surah: string; ayah: number | string };
  }>({
    from: { surah: '', ayah: '' },
    to: { surah: '', ayah: '' }
  });

  const [klasikalTilawah, setKlasikalTilawah] = useState<{
    type: 'quran' | 'iqra';
    from: { surah: string; ayah: number | string; jilid: number; halaman: number | string };
    to: { surah: string; ayah: number | string; jilid: number; halaman: number | string };
  }>({
    type: 'quran',
    from: { surah: '', ayah: '', jilid: 0, halaman: '' },
    to: { surah: '', ayah: '', jilid: 0, halaman: '' }
  });

  const [attendance, setAttendance] = useState<number>(100);
  const [behaviorScore, setBehaviorScore] = useState<number>(10);
  const [tilawahMethod, setTilawahMethod] = useState<'Al-Quran' | 'Iqra'>('Al-Quran');
  const [tilawahFromSurah, setTilawahFromSurah] = useState(''); 
  const [tilawahFromVerse, setTilawahFromVerse] = useState<number | string>(''); 
  const [tilawahToSurah, setTilawahToSurah] = useState('');
  const [tilawahToVerse, setTilawahToVerse] = useState<number | string>(''); 
  const [tilawahTotal, setTilawahTotal] = useState({ pages: 0, lines: 0 });

  const [tahfizhFromSurah, setTahfizhFromSurah] = useState(''); 
  const [tahfizhFromVerse, setTahfizhFromVerse] = useState<number | string>(''); 
  const [tahfizhToSurah, setTahfizhToSurah] = useState('');
  const [tahfizhToVerse, setTahfizhToVerse] = useState<number | string>(''); 
  const [tahfizhTotal, setTahfizhTotal] = useState({ pages: 0, lines: 0 });

  // Akumulasi Hafalan (Total)
  const [baselineJuz, setBaselineJuz] = useState<number | string>(0);
  const [baselinePages, setBaselinePages] = useState<number | string>(0);
  const [baselineLines, setBaselineLines] = useState<number | string>(0);
  const [notes, setNotes] = useState('');

  // Effect: Reset/Set Month options based on Report Type
  useEffect(() => {
    if (reportType === 'Laporan Semester') {
      if (!SEMESTER_LIST.includes(month)) {
        setMonth('Ganjil');
      }
    } else {
      if (!MONTH_LIST.includes(month)) {
        setMonth('Desember');
      }
    }
  }, [reportType]);

  // Load existing shared klasikal data when month changes
  useEffect(() => {
    const loadKlasikal = async () => {
      if (!teacherId || !month) return;
      const existing = await getHalaqahMonthlyReport(teacherId, month);
      if (existing) {
        setKlasikalTahfizh(existing.klasikal.tahfizh);
        setKlasikalTilawah({
          type: existing.klasikal.tilawah.type,
          from: { ...klasikalTilawah.from, ...existing.klasikal.tilawah.from },
          to: { ...klasikalTilawah.to, ...existing.klasikal.tilawah.to }
        });
      } else {
        // Reset ke state kosong jika tidak ada data
        setKlasikalTahfizh({ from: { surah: '', ayah: '' }, to: { surah: '', ayah: '' } });
        setKlasikalTilawah({
          type: 'quran',
          from: { surah: '', ayah: '', jilid: 0, halaman: '' },
          to: { surah: '', ayah: '', jilid: 0, halaman: '' }
        });
      }
    };
    loadKlasikal();
  }, [teacherId, month]);

  // Edit Mode Handler
  useEffect(() => {
    if (location.state?.editReportId && location.state?.reportData) {
      const r = location.state.reportData as Report;
      setStudentId(r.studentId);
      setReportType(r.type);
      setMonth(r.month);
      setAcademicYear(r.academicYear || '2025/2026');
      setAttendance(r.attendance || 100);
      setBehaviorScore(r.behaviorScore || 10);
      setNotes(r.notes || '');

      // Load Total Hafalan if exists
      if (r.totalHafalan) {
        setBaselineJuz(r.totalHafalan.juz || 0);
        setBaselinePages(r.totalHafalan.pages || 0);
        setBaselineLines(r.totalHafalan.lines || 0);
      }

      const parseRange = (range: string) => {
        if (!range || range === '-') return { fs: '', fv: '', ts: '', tv: '' };
        const parts = range.split(' - ');
        const p1 = parts[0].split(':');
        const p2 = parts[1]?.split(':') || p1;
        return { 
          fs: p1[0].trim(), 
          fv: parseInt(p1[1]) || '', 
          ts: p2[0].trim(), 
          tv: parseInt(p2[1]) || '' 
        };
      };

      const tfObj = parseRange(r.tahfizh.individual);
      setTahfizhFromSurah(tfObj.fs); setTahfizhFromVerse(tfObj.fv);
      setTahfizhToSurah(tfObj.ts); setTahfizhToVerse(tfObj.tv);

      const tlObj = parseRange(r.tilawah.individual);
      setTilawahMethod(r.tilawah.method as any || 'Al-Quran');
      setTilawahFromSurah(tlObj.fs); setTilawahFromVerse(tlObj.fv);
      setTilawahToSurah(tlObj.ts); setTilawahToVerse(tlObj.tv);
    }
  }, [location]);

  // Calculations
  const safeNum = (val: string | number) => (typeof val === 'number' ? val : 0);

  useEffect(() => {
    const result = calculateHafalan(tilawahFromSurah, safeNum(tilawahFromVerse), tilawahToSurah, safeNum(tilawahToVerse));
    setTilawahTotal(result);
  }, [tilawahMethod, tilawahFromSurah, tilawahFromVerse, tilawahToSurah, tilawahToVerse]);

  useEffect(() => {
    const result = calculateHafalan(tahfizhFromSurah, safeNum(tahfizhFromVerse), tahfizhToSurah, safeNum(tahfizhToVerse));
    setTahfizhTotal(result);
  }, [tahfizhFromSurah, tahfizhFromVerse, tahfizhToSurah, tahfizhToVerse]);

  useEffect(() => {
    if (!teacherId) return;
    setIsLoading(true);
    getStudentsByTeacher(teacherId).then(data => { setStudents(data); setIsLoading(false); });
  }, [teacherId]);

  const handleSave = async () => {
    if (!studentId) { alert("Mohon pilih siswa terlebih dahulu."); return; }
    const selectedStudent = students.find(s => s.id === studentId);
    if (!selectedStudent) return;

    setIsSaving(true);
    try {
      // Clean up klasikal data before save (convert empty strings to numbers where needed for backend compatibility if strict)
      // But Firestore handles mixed types fine.

      await saveHalaqahMonthlyReport({
        halaqahId: teacherId || '',
        teacherId: teacherId || '',
        period: month,
        academicYear,
        klasikal: {
          tahfizh: {
            from: { surah: klasikalTahfizh.from.surah, ayah: safeNum(klasikalTahfizh.from.ayah) },
            to: { surah: klasikalTahfizh.to.surah, ayah: safeNum(klasikalTahfizh.to.ayah) }
          },
          tilawah: {
            type: klasikalTilawah.type,
            from: klasikalTilawah.type === 'quran' 
              ? { surah: klasikalTilawah.from.surah, ayah: safeNum(klasikalTilawah.from.ayah) } 
              : { jilid: klasikalTilawah.from.jilid, halaman: safeNum(klasikalTilawah.from.halaman) },
            to: klasikalTilawah.type === 'quran' 
              ? { surah: klasikalTilawah.to.surah, ayah: safeNum(klasikalTilawah.to.ayah) } 
              : { jilid: klasikalTilawah.to.jilid, halaman: safeNum(klasikalTilawah.to.halaman) },
          }
        }
      });

      const fmt = (surah: string, verse: number | string) => (surah ? `${surah}: ${verse === '' ? '-' : verse}` : '-');
      const makeRange = (fs: string, fv: number | string, ts: string, tv: number | string) => (!fs && !ts ? '-' : `${fmt(fs, fv)} - ${fmt(ts, tv)}`);

      // SAVE REPORT: Selalu sertakan Total Hafalan untuk semua tipe laporan
      await saveSDQReport({
        studentId, studentName: selectedStudent.name, teacherId: teacherId || '', className: selectedStudent.className, 
        type: reportType, month, academicYear, date: new Date().toISOString().split('T')[0], evaluation: '',
        attendance, behaviorScore,
        tilawah: { method: tilawahMethod, individual: makeRange(tilawahFromSurah, tilawahFromVerse, tilawahToSurah, tilawahToVerse) },
        tahfizh: { individual: makeRange(tahfizhFromSurah, tahfizhFromVerse, tahfizhToSurah, tahfizhToVerse) },
        totalHafalan: { 
          juz: safeNum(baselineJuz), 
          pages: safeNum(baselinePages), 
          lines: safeNum(baselineLines) 
        },
        notes
      });

      alert("Laporan berhasil disimpan!");
      if (location.state?.editReportId) navigate('/guru/view-report');
      else { 
        setNotes(''); 
        // Reset individual input but keep accumulated data logic? Usually reset individual.
        setTahfizhFromVerse(''); setTahfizhToVerse('');
        setTilawahFromVerse(''); setTilawahToVerse('');
      }
    } catch (error) { console.error(error); alert("Gagal menyimpan."); } finally { setIsSaving(false); }
  };

  if (isLoading) return <div className="p-12 text-center"><Loader2 className="animate-spin mx-auto text-primary-500" size={40} /></div>;

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12">
      <div className="flex justify-between items-center px-1">
        <h2 className="text-2xl font-bold text-gray-900">{location.state?.editReportId ? 'Edit Laporan' : 'Input Laporan Halaqah'}</h2>
      </div>

      {/* FILTER SECTION */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 grid grid-cols-1 md:grid-cols-3 gap-6">
        <div>
          <label className="block text-xs font-bold text-gray-400 uppercase mb-1.5 ml-1">Tahun Ajaran</label>
          <div className="relative">
            <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-primary-500" size={14} />
            <select value={academicYear} onChange={(e) => setAcademicYear(e.target.value)} className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-xl outline-none bg-white text-sm">
              {ACADEMIC_YEARS.map(y => <option key={y} value={y}>{y}</option>)}
            </select>
          </div>
        </div>
        <div>
          <label className="block text-xs font-bold text-gray-400 uppercase mb-1.5 ml-1">Tipe Laporan</label>
          <select value={reportType} onChange={(e) => setReportType(e.target.value)} className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none bg-white text-sm">
            <option value="Laporan Bulanan">Laporan Bulanan</option>
            <option value="Laporan Semester">Laporan Semester (Individu)</option>
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-gray-400 uppercase mb-1.5 ml-1">
            {reportType === 'Laporan Semester' ? 'Semester' : 'Bulan Periode'}
          </label>
          <select value={month} onChange={(e) => setMonth(e.target.value)} className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none bg-white text-sm">
            {reportType === 'Laporan Semester' 
              ? SEMESTER_LIST.map(m => <option key={m} value={m}>Semester {m}</option>)
              : MONTH_LIST.map(m => <option key={m} value={m}>{m}</option>)
            }
          </select>
        </div>
      </div>

      {/* SECTION KLASIKAL (Shared) */}
      <div className="bg-white rounded-[2rem] shadow-sm border-2 border-primary-50 overflow-hidden">
        <div className="bg-primary-50 px-6 py-4 flex items-center justify-between border-b border-primary-100">
           <div className="flex items-center gap-3"><Layers className="text-primary-600" /><div><h3 className="font-bold text-primary-900 text-sm uppercase">Capaian Klasikal Halaqah</h3></div></div>
        </div>
        <div className="p-6 space-y-8">
           {/* Tahfizh Klasikal */}
           <div className="space-y-4">
              <h4 className="text-[11px] font-black text-gray-700 uppercase tracking-widest flex items-center gap-2"><Book size={14} className="text-emerald-500" /> Tahfizh Klasikal</h4>
              <div className="flex flex-col md:flex-row gap-4 items-end bg-gray-50/50 p-4 rounded-2xl border border-gray-100">
                 <div className="flex-1 space-y-2"><p className="text-[10px] font-bold text-gray-400 ml-1 uppercase">Dari</p>
                    <div className="flex gap-2">
                       <SourceSelect placeholder="Pilih..." value={klasikalTahfizh.from.surah} onChange={v => setKlasikalTahfizh({...klasikalTahfizh, from: {...klasikalTahfizh.from, surah: v}})} method="Al-Quran" />
                       <CounterInput label="Ayat" value={klasikalTahfizh.from.ayah} onChange={v => setKlasikalTahfizh({...klasikalTahfizh, from: {...klasikalTahfizh.from, ayah: v}})} />
                    </div>
                 </div>
                 <div className="flex-1 space-y-2"><p className="text-[10px] font-bold text-gray-400 ml-1 uppercase">Sampai</p>
                    <div className="flex gap-2">
                       <SourceSelect placeholder="Pilih..." value={klasikalTahfizh.to.surah} onChange={v => setKlasikalTahfizh({...klasikalTahfizh, to: {...klasikalTahfizh.to, surah: v}})} method="Al-Quran" />
                       <CounterInput label="Ayat" value={klasikalTahfizh.to.ayah} onChange={v => setKlasikalTahfizh({...klasikalTahfizh, to: {...klasikalTahfizh.to, ayah: v}})} />
                    </div>
                 </div>
              </div>
           </div>

           {/* Tilawah Klasikal */}
           <div className="space-y-4">
              <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4">
                <h4 className="text-[11px] font-black text-gray-700 uppercase tracking-widest flex items-center gap-2"><BookOpen size={14} className="text-blue-500" /> Tilawah Klasikal</h4>
                <div className="flex bg-gray-100 p-1 rounded-xl gap-1">
                    <button type="button" onClick={() => setKlasikalTilawah({...klasikalTilawah, type: 'quran'})} className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${klasikalTilawah.type === 'quran' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}>Al-Qur'an</button>
                    <button type="button" onClick={() => setKlasikalTilawah({...klasikalTilawah, type: 'iqra'})} className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${klasikalTilawah.type === 'iqra' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}>Iqra'</button>
                 </div>
              </div>
              <div className="flex flex-col md:flex-row gap-4 items-end bg-gray-50/50 p-4 rounded-2xl border border-gray-100 transition-all">
                 {klasikalTilawah.type === 'quran' ? (
                    <>
                      <div className="flex-1 space-y-2"><p className="text-[10px] font-bold text-gray-400 ml-1 uppercase">Dari</p>
                        <div className="flex gap-2">
                          <SourceSelect placeholder="Pilih..." value={klasikalTilawah.from.surah} onChange={v => setKlasikalTilawah({...klasikalTilawah, from: {...klasikalTilawah.from, surah: v}})} method="Al-Quran" />
                          <CounterInput label="Ayat" value={klasikalTilawah.from.ayah} onChange={v => setKlasikalTilawah({...klasikalTilawah, from: {...klasikalTilawah.from, ayah: v}})} />
                        </div>
                      </div>
                      <div className="flex-1 space-y-2"><p className="text-[10px] font-bold text-gray-400 ml-1 uppercase">Sampai</p>
                        <div className="flex gap-2">
                          <SourceSelect placeholder="Pilih..." value={klasikalTilawah.to.surah} onChange={v => setKlasikalTilawah({...klasikalTilawah, to: {...klasikalTilawah.to, surah: v}})} method="Al-Quran" />
                          <CounterInput label="Ayat" value={klasikalTilawah.to.ayah} onChange={v => setKlasikalTilawah({...klasikalTilawah, to: {...klasikalTilawah.to, ayah: v}})} />
                        </div>
                      </div>
                    </>
                 ) : (
                    <>
                      <div className="flex-1 space-y-2"><p className="text-[10px] font-bold text-gray-400 ml-1 uppercase">Dari</p>
                        <div className="flex gap-2">
                          <select value={klasikalTilawah.from.jilid || ''} onChange={e => setKlasikalTilawah({...klasikalTilawah, from: {...klasikalTilawah.from, jilid: parseInt(e.target.value)}})} className="flex-1 p-2 border border-gray-200 rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500">
                            <option value="">Pilih...</option>
                            {IQRA_JILIDS.map(j => <option key={j} value={j}>Iqra' {j}</option>)}
                          </select>
                          <CounterInput label="Hal" value={klasikalTilawah.from.halaman} onChange={v => setKlasikalTilawah({...klasikalTilawah, from: {...klasikalTilawah.from, halaman: v}})} />
                        </div>
                      </div>
                      <div className="flex-1 space-y-2"><p className="text-[10px] font-bold text-gray-400 ml-1 uppercase">Sampai</p>
                        <div className="flex gap-2">
                          <select value={klasikalTilawah.to.jilid || ''} onChange={e => setKlasikalTilawah({...klasikalTilawah, to: {...klasikalTilawah.to, jilid: parseInt(e.target.value)}})} className="flex-1 p-2 border border-gray-200 rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500">
                            <option value="">Pilih...</option>
                            {IQRA_JILIDS.map(j => <option key={j} value={j}>Iqra' {j}</option>)}
                          </select>
                          <CounterInput label="Hal" value={klasikalTilawah.to.halaman} onChange={v => setKlasikalTilawah({...klasikalTilawah, to: {...klasikalTilawah.to, halaman: v}})} />
                        </div>
                      </div>
                    </>
                 )}
              </div>
           </div>
        </div>
      </div>

      {/* SECTION INDIVIDUAL SISWA */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 space-y-6 border-t-4 border-t-emerald-500">
        <div className="flex items-center gap-2 mb-2"><UserCheck className="text-emerald-600" /><h3 className="font-bold text-gray-800 text-sm uppercase">Capaian Individu Siswa</h3></div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div><label className="block text-xs font-bold text-gray-400 uppercase mb-1.5 ml-1">Pilih Siswa</label><select value={studentId} onChange={(e) => setStudentId(e.target.value)} className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none bg-white text-sm"><option value="">-- Pilih Siswa --</option>{students.map(s => <option key={s.id} value={s.id}>{s.name} - {s.className}</option>)}</select></div>
          <div className="grid grid-cols-2 gap-4">
             <div className="space-y-2"><label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Kehadiran</label><select value={attendance} onChange={e => setAttendance(Number(e.target.value))} className="w-full p-2 border rounded-lg text-sm bg-white"><option value={97}>Sangat Baik</option><option value={90}>Baik</option><option value={80}>Cukup</option><option value={60}>Perhatian</option></select></div>
             <div className="space-y-2"><label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Adab</label><select value={behaviorScore} onChange={e => setBehaviorScore(Number(e.target.value))} className="w-full p-2 border rounded-lg text-sm bg-white"><option value={10}>Sangat Baik</option><option value={8}>Baik</option><option value={6}>Pembinaan</option></select></div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pt-4 border-t border-gray-50">
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h4 className="text-xs font-bold text-emerald-700 flex items-center gap-2">
                <Book size={16} className="text-emerald-500" /> Setoran Sabaq Individu
              </h4>
              <span className="text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded uppercase tracking-tighter">Total: {tahfizhTotal.pages} Hal {tahfizhTotal.lines} Baris</span>
            </div>
            <InputRow label="DARI"><SourceSelect value={tahfizhFromSurah} onChange={(v) => {setTahfizhFromSurah(v); if(!tahfizhToSurah) setTahfizhToSurah(v);}} method="Al-Quran" /><CounterInput label="Ayat" value={tahfizhFromVerse} onChange={setTahfizhFromVerse} /></InputRow>
            <InputRow label="SAMPAI"><SourceSelect value={tahfizhToSurah} onChange={setTahfizhToSurah} method="Al-Quran" /><CounterInput label="Ayat" value={tahfizhToVerse} onChange={setTahfizhToVerse} /></InputRow>
          </div>
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h4 className="text-xs font-bold text-blue-700 flex items-center gap-2">
                <BookOpen size={16} className="text-blue-500" /> Tilawah Individu
              </h4>
              <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded uppercase tracking-tighter">Total: {tilawahTotal.pages} Hal {tilawahTotal.lines} Baris</span>
            </div>
            <div className="flex gap-2"><button onClick={() => setTilawahMethod('Al-Quran')} className={`flex-1 py-1 text-[9px] font-bold rounded-lg ${tilawahMethod === 'Al-Quran' ? 'bg-blue-600 text-white' : 'bg-gray-50 text-gray-400'}`}>AL-QUR'AN</button><button onClick={() => setTilawahMethod('Iqra')} className={`flex-1 py-1 text-[9px] font-bold rounded-lg ${tilawahMethod === 'Iqra' ? 'bg-blue-600 text-white' : 'bg-gray-50 text-gray-400'}`}>IQRA'</button></div>
            <InputRow label="DARI"><SourceSelect value={tilawahFromSurah} onChange={(v) => {setTilawahFromSurah(v); if(!tilawahToSurah) setTilawahToSurah(v);}} method={tilawahMethod} /><CounterInput label={tilawahMethod === 'Al-Quran' ? 'Ayat' : 'Hal'} value={tilawahFromVerse} onChange={setTilawahFromVerse} /></InputRow>
            <InputRow label="SAMPAI"><SourceSelect value={tilawahToSurah} onChange={setTilawahToSurah} method={tilawahMethod} /><CounterInput label={tilawahMethod === 'Al-Quran' ? 'Ayat' : 'Hal'} value={tilawahToVerse} onChange={setTilawahToVerse} /></InputRow>
          </div>
        </div>

        {/* AKUMULASI HAFALAN - TAMPIL UNTUK SEMUA LAPORAN */}
        <div className="bg-emerald-50/30 p-4 rounded-xl border border-emerald-100/50">
          <div className="flex items-center gap-2 mb-4"><Database size={16} className="text-emerald-600"/><h4 className="font-bold text-emerald-800 text-xs tracking-widest uppercase">Akumulasi Hafalan (Total)</h4></div>
          <div className="grid grid-cols-3 gap-2">
