                <Route path="/guru/evaluation" render={() => <GuruEvaluationPage teacherId={user?.id} />} />
                <Route path="/guru/grades" render={() => <GuruGradesPage teacherId={user?.id} />} />
                <Route path="/guru/rapor" render={() => <GuruRaporPage teacherId={user?.id} teacherName={user?.name} />} />

                <Redirect to="/" />
             </Switch>
           </Layout>
        </Route>
      </Switch>
    </HashRouter>
  );
}

