                      <div key={index} className="px-3 pt-6 pb-2">
                         <p className="text-xs font-semibold text-white/50 uppercase tracking-wider">{item.label}</p>
                      </div>
                    );
                  }

                  if (!item.to) return null;

                  return (
                    <NavLink
                      key={item.to}
                      to={item.to}
                      exact={item.to.split('/').length === 2}
                      onClick={() => setSidebarOpen(false)}
                      activeClassName={sidebarActive}
                      className={`
                        flex items-center justify-between px-3 py-3 rounded-lg transition-colors mb-1 group text-white/80 ${sidebarHover}
