            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 flex items-center gap-1.5"><BookOpen size={12} /> {filterType === 'Laporan Bulanan' ? 'Pilih Bulan' : 'Pilih Semester'}</label>
            {filterType === 'Laporan Bulanan' ? (
              <select value={filterMonth} onChange={(e) => setFilterMonth(e.target.value)} className="w-full px-4 py-2.5 border border-gray-200 rounded-xl bg-gray-50 text-sm font-bold outline-none">{MONTHS.map(m => <option key={m} value={m}>{m}</option>)}</select>
            ) : (
              <select value={filterSemester} onChange={(e) => setFilterSemester(e.target.value)} className="w-full px-4 py-2.5 border border-gray-200 rounded-xl bg-gray-50 text-sm font-bold outline-none"><option value="Ganjil">Semester 1 (Ganjil)</option><option value="Genap">Semester 2 (Genap)</option></select>
            )}
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 flex items-center gap-1.5"><Search size={12} /> Cari Santri</label>
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-300" size={18} />
              <input type="text" placeholder="Ketik nama siswa..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full pl-10 pr-4 py-2.5 border border-gray-200 rounded-xl bg-gray-50 text-sm focus:ring-2 focus:ring-primary-500 outline-none" />
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse whitespace-nowrap">
            <thead>
              <tr className="bg-[#0e7490] text-white text-[11px] uppercase font-black tracking-wider text-center">
                <th rowSpan={2} className="px-4 py-4 border-r border-white/10">Nama Siswa</th>
                <th rowSpan={2} className="px-4 py-4 border-r border-white/10">Jml Hafalan</th>
                <th colSpan={3} className="px-4 py-3 border-r border-white/10 border-b border-white/10">Tilawah</th>
                <th colSpan={3} className="px-4 py-3 border-r border-white/10 border-b border-white/10">Tahfizh</th>
                <th rowSpan={2} className="px-4 py-4 border-r border-white/10">Keterangan</th>
                <th rowSpan={2} className="px-4 py-4 border-r border-white/10">Catatan</th>
                <th rowSpan={2} className="px-4 py-4">Aksi</th>
              </tr>
              <tr className="bg-[#155e75] text-white text-[9px] uppercase font-black tracking-widest text-center">
                <th className="px-2 py-3 border-r border-white/5">Klasikal</th>
                <th className="px-2 py-3 border-r border-white/5">Individual</th>
                <th className="px-2 py-3 border-r border-white/10">Hasil</th>
                <th className="px-2 py-3 border-r border-white/5">Klasikal</th>
                <th className="px-2 py-3 border-r border-white/5">Individual</th>
                <th className="px-2 py-3 border-r border-white/10">Hasil</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 text-[11px]">
              {isLoading ? (
                <tr><td colSpan={11} className="px-6 py-20 text-center"><Loader2 size={32} className="text-primary-500 animate-spin mx-auto" /></td></tr>
              ) : filteredReports.length > 0 ? (
                filteredReports.map((report) => {
                  const globalKlasikal = klasikalMap[report.month]?.klasikal;
                  const resTahfizh = formatKlasikalDisplay(globalKlasikal || report.tahfizh.classical, 'tahfizh');
                  const resTilawah = formatKlasikalDisplay(globalKlasikal || report.tilawah.classical, 'tilawah');

                  const compactIndividualTahfizh = formatCompactRangeString(report.tahfizh.individual);
                  const compactIndividualTilawah = formatCompactRangeString(report.tilawah.individual);

                  const effectiveTahfizhRange = (report.tahfizh.individual && report.tahfizh.individual !== '-') ? report.tahfizh.individual : resTahfizh.text;
                  const effectiveTilawahRange = (report.tilawah.individual && report.tilawah.individual !== '-') ? report.tilawah.individual : resTilawah.text;

                  return (
                    <tr key={report.id} className="hover:bg-gray-50/50 transition-colors group">
                      <td className="px-4 py-4 border-r border-gray-50">
                        <div className="font-black text-gray-900 uppercase">{report.studentName}</div>
                      </td>
                      <td className="px-4 py-4 border-r border-gray-50 text-center font-black text-teal-700 bg-teal-50/20">{formatTotalHafalan(report.totalHafalan)}</td>

                      {/* TILAWAH */}
                      <td className="px-2 py-4 border-r border-gray-50 text-center text-gray-400 italic font-medium whitespace-normal min-w-[100px]">{resTilawah.text}</td>
                      <td className="px-2 py-4 border-r border-gray-50 text-center font-bold text-gray-700">{compactIndividualTilawah}</td>
                      <td className="px-2 py-4 border-r border-gray-50 text-center font-black text-blue-600 bg-blue-50/30">{getCalculationDisplay(effectiveTilawahRange)}</td>

                      {/* TAHFIZH */}
                      <td className="px-2 py-4 border-r border-gray-50 text-center text-gray-400 italic font-medium whitespace-normal min-w-[100px]">{resTahfizh.text}</td>
                      <td className="px-2 py-4 border-r border-gray-50 text-center font-bold text-gray-700">{compactIndividualTahfizh}</td>
                      <td className="px-2 py-4 border-r border-gray-50 text-center font-black text-emerald-600 bg-emerald-50/30">{getCalculationDisplay(effectiveTahfizhRange)}</td>

                      {/* STATUS & NOTES */}
                      <td className="px-4 py-4 border-r border-gray-50 text-center">{getStatusBadge(effectiveTahfizhRange, report.type)}</td>
                      <td className="px-4 py-4 border-r border-gray-50 min-w-[150px]"><div className="text-gray-500 italic max-w-[200px] whitespace-normal line-clamp-2 leading-relaxed">"{report.notes || "-"}</div></td>

                      {/* AKSI */}
                      <td className="px-4 py-4 text-center">
                        <div className="flex gap-2 justify-center">
                           <button onClick={() => handleEditReport(report)} className="p-2 text-primary-600 hover:bg-primary-50 rounded-xl transition-all shadow-sm bg-white border border-gray-100" title="Edit Laporan"><Edit2 size={14} /></button>
                           <button onClick={() => { if(confirm("Hapus laporan ini?")) deleteReport(report.id); }} className="p-2 text-rose-500 hover:bg-rose-50 rounded-xl transition-all shadow-sm bg-white border border-gray-100" title="Hapus Laporan"><Trash2 size={14} /></button>
                        </div>
                      </td>
                    </tr>
                  );
                })
              ) : (
                <tr><td colSpan={11} className="px-6 py-24 text-center text-gray-400 uppercase tracking-widest font-black text-xs italic">Data Laporan Tidak Ditemukan</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default withRouter(GuruViewReportPage);

import React, { useEffect, useState } from 'react';
import { withRouter, RouteComponentProps } from 'react-router-dom';
import { Student, SemesterReport } from '../../../types';
import { getStudentsByTeacher, saveSemesterReport, getSemesterReport } from '../../../services/firestoreService';
import { improveReportRedaction, improveTeacherNotes } from '../../../services/geminiService';
import { extractClassLevel } from '../../../services/sdqTargets';
import { Button } from '../../../components/Button';
import { Save, BookOpen, ClipboardCheck, GraduationCap, User, FileText, Info, Sparkles, Loader2, MessageSquare } from 'lucide-react';

interface GuruGradesProps extends RouteComponentProps {
  teacherId?: string;
}

const GuruGradesPage: React.FC<GuruGradesProps> = ({ teacherId, location }) => {
  const [students, setStudents] = useState<Student[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isRefining, setIsRefining] = useState<{ [key: string]: boolean }>({});

  const [report, setReport] = useState<SemesterReport>({
    studentId: '',
    teacherId: teacherId || '',
    academicYear: '2025 / 2026',
    semester: 'Ganjil',
    targetHafalan: '10 Halaman',
    dateStr: '',
    dateHijri: '',
    assessments: { adab: 'B', murojaah: 'B', tajwid: 'B', makharij: 'A', pencapaianTarget: 85 },
    exams: { uts: 80, uas: 80 },
    statusHafalan: {
      dimiliki: { jumlah: '', rincian: '', status: 'Cukup Baik' },
      mutqin: { jumlah: '', rincian: '', status: 'Cukup Baik' },
      semesterIni: { jumlah: '', rincian: '', status: 'Baik' }
    },
    narrativeTahfizh: '',
    narrativeTilawah: '',
    notes: ''
  });

  useEffect(() => {
    if (teacherId) {
      getStudentsByTeacher(teacherId).then(data => {
        setStudents(data);
        const state = location.state as any;
        const stateId = state?.studentId;
        if (stateId) handleStudentChange(stateId, data);
      });
    }
  }, [teacherId, location]);

  const handleStudentChange = async (id: string, currentStudents?: Student[]) => {
    if (!id) {
      setSelectedStudent(null);
      return;
    }

    const student = (currentStudents || students).find(s => s.id === id);
    setSelectedStudent(student || null);

    setIsLoading(true);
    const existing = await getSemesterReport(id, report.academicYear, report.semester);
    if (existing) {
      setReport(existing);
    } else {
      setReport(prev => ({
        ...prev,
        studentId: id,
        teacherId: teacherId || '',
        narrativeTahfizh: '',
        narrativeTilawah: '',
        notes: `Tingkatkan kembali semangat Ananda ${student?.name || ''} dalam menghafal serta memuroja'ah hafalan. Semoga Allah selalu memberikan kemudahan.`
      }));
    }
    setIsLoading(false);
  };

  const handleRefineLanguage = async (field: 'narrativeTahfizh' | 'narrativeTilawah' | 'notes') => {
    const text = (report as any)[field];
    if (!text || text.trim().length < 10) {
      alert("Silakan tulis deskripsi minimal satu kalimat terlebih dahulu.");
      return;
    }

    setIsRefining(prev => ({ ...prev, [field]: true }));
    try {
      let refinedText = "";
      if (field === 'notes') {
        refinedText = await improveTeacherNotes(text);
      } else {
        refinedText = await improveReportRedaction(text);
      }
      setReport(prev => ({ ...prev, [field]: refinedText }));
    } catch (error: any) {
      alert(error.message);
    } finally {
      setIsRefining(prev => ({ ...prev, [field]: false }));
    }
  };

  const handleSave = async () => {
    if (!selectedStudent) return alert("Pilih siswa!");
    setIsSaving(true);
    try {
      await saveSemesterReport({ ...report, studentId: selectedStudent.id, teacherId: teacherId || '' });
      alert("Data rapor berhasil disimpan.");
    } catch (e) {
      alert("Gagal menyimpan data.");
    } finally {
      setIsSaving(false);
    }
  };

  const classLevel = selectedStudent ? extractClassLevel(selectedStudent.className) : 0;
  const isDescriptionFormat = classLevel >= 1 && classLevel <= 3;

  const getPredikatLetter = (letter: string) => {
    if (letter === 'A') return 'Mumtaz';
    if (letter === 'B') return 'Jayyid Jiddan';
    if (letter === 'C') return 'Jayyid';
    return '-';
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-20">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold text-gray-900 mb-4 flex items-center gap-2">
          <GraduationCap className="text-primary-600" /> Input Nilai Rapor Semester
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="md:col-span-1">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1 ml-1">Pilih Siswa ({students.length})</label>
            <select 
              value={selectedStudent?.id || ''} 
              onChange={(e) => handleStudentChange(e.target.value)}
              className="w-full px-4 py-2.5 border border-gray-200 rounded-xl bg-white focus:ring-2 focus:ring-primary-500 outline-none text-sm"
            >
              <option value="">-- Pilih Siswa --</option>
              {students.map(s => <option key={s.id} value={s.id}>{s.name} - {s.className}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1 ml-1">Tahun Ajaran</label>
            <select 
              value={report.academicYear} 
              onChange={e => setReport({...report, academicYear: e.target.value})} 
              className="w-full px-4 py-2.5 border border-gray-200 rounded-xl text-sm bg-white"
            >
              <option value="2024 / 2025">2024 / 2025</option>
              <option value="2025 / 2026">2025 / 2026</option>
              <option value="2026 / 2027">2026 / 2027</option>
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1 ml-1">Semester</label>
            <select value={report.semester} onChange={e => setReport({...report, semester: e.target.value as any})} className="w-full px-4 py-2.5 border border-gray-200 rounded-xl text-sm">
              <option value="Ganjil">Ganjil</option>
              <option value="Genap">Genap</option>
            </select>
          </div>
        </div>

        {selectedStudent && (
          <div className="mt-4 p-3 bg-blue-50 rounded-xl border border-blue-100 flex items-center gap-3 text-blue-700 text-xs font-bold">
            <Info size={16} />
            Siswa Kelas {classLevel}. Menggunakan format: {isDescriptionFormat ? 'RAPOR DESKRIPSI' : 'RAPOR TABEL'}
          </div>
        )}
      </div>

      {isLoading ? (
        <div className="text-center py-12 text-gray-500">Memuat data...</div>
      ) : selectedStudent && (
        <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-500">

          {isDescriptionFormat ? (
            <div className="space-y-6">
              {/* Narasi Tahfizh */}
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50 px-6 py-3 border-b border-gray-100 flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <FileText size={18} className="text-primary-600" />
                    <h3 className="font-bold text-gray-800 text-sm uppercase">A. Perkembangan Tahfizh</h3>
                  </div>
                  <button 
                    onClick={() => handleRefineLanguage('narrativeTahfizh')}
                    disabled={isRefining['narrativeTahfizh'] || !report.narrativeTahfizh}
                    className="flex items-center gap-1.5 px-3 py-1 bg-primary-50 hover:bg-primary-100 text-primary-600 rounded-lg text-[10px] font-black uppercase tracking-wider transition-all disabled:opacity-50"
                  >
                    {isRefining['narrativeTahfizh'] ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                    Sempurnakan Bahasa (AI)
                  </button>
                </div>
                <div className="p-6">
                   <textarea 
                     value={report.narrativeTahfizh}
                     onChange={e => setReport({...report, narrativeTahfizh: e.target.value})}
                     className="w-full p-4 border border-gray-200 rounded-xl text-sm h-48 focus:ring-2 focus:ring-primary-500 outline-none leading-relaxed transition-all"
                     placeholder="Tuliskan perkembangan hafalan siswa... (Contoh: Tahfiz ananda masih kurang lancar dan sering lupa ayat)"
                   />
                </div>
              </div>

              {/* Narasi Tilawah */}
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50 px-6 py-3 border-b border-gray-100 flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <BookOpen size={18} className="text-primary-600" />
                    <h3 className="font-bold text-gray-800 text-sm uppercase">B. Perkembangan Tilawah</h3>
                  </div>
                  <button 
                    onClick={() => handleRefineLanguage('narrativeTilawah')}
                    disabled={isRefining['narrativeTilawah'] || !report.narrativeTilawah}
                    className="flex items-center gap-1.5 px-3 py-1 bg-primary-50 hover:bg-primary-100 text-primary-600 rounded-lg text-[10px] font-black uppercase tracking-wider transition-all disabled:opacity-50"
                  >
                    {isRefining['narrativeTilawah'] ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                    Sempurnakan Bahasa (AI)
                  </button>
                </div>
                <div className="p-6">
                   <textarea 
                     value={report.narrativeTilawah}
                     onChange={e => setReport({...report, narrativeTilawah: e.target.value})}
                     className="w-full p-4 border border-gray-200 rounded-xl text-sm h-48 focus:ring-2 focus:ring-primary-500 outline-none leading-relaxed transition-all"
                     placeholder="Tuliskan perkembangan tilawah siswa..."
                   />
                </div>
              </div>
            </div>
          ) : (
            <>
              {/* Aspek Penilaian */}
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50 px-6 py-3 border-b border-gray-100 flex items-center gap-2">
                  <ClipboardCheck size={18} className="text-primary-600" />
                  <h3 className="font-bold text-gray-800 text-sm">ASPEK PENILAIAN (A/B/C)</h3>
                </div>
                <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {[
                    { id: 'adab', label: 'Adab di Halaqah' },
                    { id: 'murojaah', label: 'Muroja\'ah' },
                    { id: 'tajwid', label: 'Tajwid' },
                    { id: 'makharij', label: 'Makharijul Huruf' },
                  ].map(item => (
                    <div key={item.id}>
                      <label className="block text-xs font-bold text-gray-500 mb-1">{item.label}</label>
                      <div className="flex items-center gap-3">
                        <select 
                          value={(report.assessments as any)[item.id]} 
                          onChange={e => setReport({...report, assessments: {...report.assessments, [item.id]: e.target.value}})}
                          className="flex-1 px-3 py-2 border border-gray-200 rounded-lg text-sm"
                        >
                          <option value="A">A</option>
                          <option value="B">B</option>
                          <option value="C">C</option>
                        </select>
                        <span className="text-[10px] font-bold text-gray-400 italic shrink-0 w-20">{getPredikatLetter((report.assessments as any)[item.id])}</span>
                      </div>
                    </div>
                  ))}
                  <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">Target Hafalan</label>
                    <input type="text" value={report.targetHafalan} onChange={e => setReport({...report, targetHafalan: e.target.value})} className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">Pencapaian Target (%)</label>
                    <input type="number" value={report.assessments.pencapaianTarget} onChange={e => setReport({...report, assessments: {...report.assessments, pencapaianTarget: parseInt(e.target.value) || 0}})} className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm" />
                  </div>
                </div>
              </div>

              {/* Ujian */}
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50 px-6 py-3 border-b border-gray-100 flex items-center gap-2">
                  <BookOpen size={18} className="text-primary-600" />
                  <h3 className="font-bold text-gray-800 text-sm">UJIAN-UJIAN (ANGKA 0-100)</h3>
                </div>
                <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">Ujian Tengah Semester (UTS)</label>
                    <input type="number" value={report.exams.uts} onChange={e => setReport({...report, exams: {...report.exams, uts: parseInt(e.target.value) || 0}})} className="w-32 px-3 py-2 border border-gray-200 rounded-lg text-sm font-bold" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">Ujian Akhir Semester (UAS)</label>
                    <input type="number" value={report.exams.uas} onChange={e => setReport({...report, exams: {...report.exams, uas: parseInt(e.target.value) || 0}})} className="w-32 px-3 py-2 border border-gray-200 rounded-lg text-sm font-bold" />
                  </div>
                </div>
              </div>

              {/* Status Hafalan */}
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50 px-6 py-3 border-b border-gray-100 flex items-center gap-2">
                  <User size={18} className="text-primary-600" />
                  <h3 className="font-bold text-gray-800 text-sm">STATUS HAFALAN SISWA</h3>
                </div>
                <div className="p-6 space-y-4">
                  {['dimiliki', 'mutqin', 'semesterIni'].map((k, idx) => (
                    <div key={k} className="flex flex-col md:flex-row gap-4 md:items-center">
                       <p className="w-44 text-xs font-bold text-gray-600 uppercase">
                          {idx === 0 ? "Total Hafalan Dimiliki" : idx === 1 ? "Hafalan Mutqin" : "Hafalan Semester Ini"}
                       </p>
                       <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-2">
                          <input 
                            value={(report.statusHafalan as any)[k].jumlah} 
                            onChange={e => setReport({...report, statusHafalan: {...report.statusHafalan, [k]: {...(report.statusHafalan as any)[k], jumlah: e.target.value}}})} 
                            className="p-2 border rounded-lg text-xs" 
                            placeholder="Jumlah (Contoh: 1 Juz 3 Hal)" 
                          />
                          <input 
                            value={(report.statusHafalan as any)[k].rincian} 
                            onChange={e => setReport({...report, statusHafalan: {...report.statusHafalan, [k]: {...(report.statusHafalan as any)[k], rincian: e.target.value}}})} 
                            className="p-2 border rounded-lg text-xs" 
                            placeholder="Rincian (Contoh: 30 dan 29)" 
                          />
                          <input 
                            value={(report.statusHafalan as any)[k].status} 
                            onChange={e => setReport({...report, statusHafalan: {...report.statusHafalan, [k]: {...(report.statusHafalan as any)[k], status: e.target.value}}})} 
                            className="p-2 border rounded-lg text-xs" 
                            placeholder="Status (Contoh: Baik)" 
                          />
                       </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* Catatan Guru (Khusus 4-6) */}
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50 px-6 py-3 border-b border-gray-100 flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <MessageSquare size={18} className="text-primary-600" />
                    <h3 className="font-bold text-gray-800 text-sm">CATATAN WALI KELAS</h3>
                  </div>
                  <button 
                    onClick={() => handleRefineLanguage('notes')}
                    disabled={isRefining['notes'] || !report.notes}
                    className="flex items-center gap-1.5 px-3 py-1 bg-primary-50 hover:bg-primary-100 text-primary-600 rounded-lg text-[10px] font-black uppercase tracking-wider transition-all disabled:opacity-50"
                  >
                    {isRefining['notes'] ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                    Sempurnakan Catatan (AI)
                  </button>
                </div>
                <div className="p-6">
                   <textarea 
                     value={report.notes}
                     onChange={e => setReport({...report, notes: e.target.value})}
                     className="w-full p-4 border border-gray-200 rounded-xl text-sm h-32 focus:ring-2 focus:ring-primary-500 outline-none leading-relaxed transition-all"
                     placeholder="Tuliskan catatan pembinaan untuk siswa... (Contoh: Ananda cukup baik tapi masih sering tidak fokus)"
                   />
                </div>
              </div>
            </>
          )}

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Tanggal (Masehi)</label>
                <input type="text" placeholder="Contoh: 22 Desember 2025" value={report.dateStr} onChange={e => setReport({...report, dateStr: e.target.value})} className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm" />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Tanggal (Hijriah)</label>
                <input type="text" placeholder="Contoh: 01 Jumadil Akhir 1447 H" value={report.dateHijri} onChange={e => setReport({...report, dateHijri: e.target.value})} className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm" />
              </div>
            </div>
          </div>

          <Button onClick={handleSave} isLoading={isSaving} className="w-full py-4 rounded-2xl shadow-xl shadow-primary-500/20 font-bold">
            <Save size={20} /> Simpan Seluruh Data Rapor
          </Button>
        </div>
      )}
    </div>
  );
}

