const MONTH_LIST = ["Juli", "Agustus", "September", "Oktober", "November", "Desember", "Januari", "Februari", "Maret", "April", "Mei", "Juni"];
const SEMESTER_LIST = ["Ganjil", "Genap"];
const ACADEMIC_YEARS = ["2024/2025", "2025/2026", "2026/2027"];

const CounterInput = ({ 
  label, 
  value, 
  onChange, 
  min = 0 
}: { 
  label?: string, 
  value: number | string, 
  onChange: (v: number | string) => void, 
  min?: number 
}) => {
  const handleDec = () => {
    const current = typeof value === 'number' ? value : 0;
    onChange(Math.max(min, current - 1));
  };

  const handleInc = () => {
    const current = typeof value === 'number' ? value : 0;
    onChange(current + 1);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (val === '') {
      onChange('');
    } else {
      onChange(parseInt(val) || 0);
    }
  };

  return (
    <div className="flex items-center gap-1 sm:gap-2 shrink-0">
      <button 
        type="button"
        onClick={handleDec} 
        className="w-8 h-9 rounded-lg border border-gray-200 flex items-center justify-center text-gray-400 hover:bg-gray-50 active:bg-gray-100 transition-colors shadow-sm"
      >
        <Minus size={14} />
      </button>
      <input 
        type="number" 
        min={min} 
        value={value} 
        onChange={handleChange} 
        placeholder="0"
        className="w-12 text-center font-bold border border-gray-100 py-1.5 rounded-lg bg-white focus:ring-2 focus:ring-primary-500 outline-none text-sm shadow-sm placeholder:text-gray-300" 
      />
      <button 
        type="button"
        onClick={handleInc} 
        className="w-8 h-9 rounded-lg border border-gray-200 flex items-center justify-center text-gray-400 hover:bg-gray-50 active:bg-gray-100 transition-colors shadow-sm"
      >
        <Plus size={14} />
      </button>
      {label && <span className="text-[10px] text-gray-400 ml-0.5 font-medium uppercase">{label}</span>}
    </div>
  );
};

